import { useEffect, useRef, useState } from "react";
import toast from "react-hot-toast";
import { PenLine, RotateCcw, CheckCircle2 } from "lucide-react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/Dialog";
import { Button } from "@/components/ui/Button";
import { Checkbox } from "@/components/ui/checkbox";

const PAD_WIDTH = 720;
const PAD_HEIGHT = 240;

const ContractSignModal = ({
  open,
  onOpenChange,
  onSubmit,
  loading = false,
  contractVersion,
}) => {
  const canvasRef = useRef(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [hasStroke, setHasStroke] = useState(false);
  const [acceptedTerms, setAcceptedTerms] = useState(false);

  useEffect(() => {
    if (!open) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#f8fafc";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    ctx.strokeStyle = "#0f172a";
    ctx.lineWidth = 2;
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    setHasStroke(false);
    setAcceptedTerms(false);
  }, [open]);

  const pointFromEvent = (event) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    return {
      x: ((event.clientX - rect.left) / rect.width) * canvas.width,
      y: ((event.clientY - rect.top) / rect.height) * canvas.height,
    };
  };

  const drawStart = (event) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const p = pointFromEvent(event);
    ctx.beginPath();
    ctx.moveTo(p.x, p.y);
    setIsDrawing(true);
    setHasStroke(true);
  };

  const drawMove = (event) => {
    if (!isDrawing) return;
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    const p = pointFromEvent(event);
    ctx.lineTo(p.x, p.y);
    ctx.stroke();
  };

  const drawEnd = () => {
    setIsDrawing(false);
  };

  const clearSignature = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#f8fafc";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    setHasStroke(false);
  };

  const handleConfirm = async () => {
    if (!acceptedTerms) {
      toast.error("Bạn cần đồng ý điều khoản trước khi ký");
      return;
    }

    if (!hasStroke) {
      toast.error("Vui lòng ký vào khung chữ ký");
      return;
    }

    const canvas = canvasRef.current;
    const signatureData = canvas.toDataURL("image/png");

    try {
      await onSubmit?.({
        acceptedTerms: true,
        signatureData,
        signedAt: new Date().toISOString(),
        contractVersion,
        signerMetadata: {
          userAgent: navigator.userAgent,
          timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
        },
      });
      onOpenChange?.(false);
    } catch {
      // caller handles API errors
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-3xl">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <PenLine className="h-4 w-4 text-primary" />
            Ký hợp đồng điện tử
          </DialogTitle>
          <DialogDescription>
            Xác nhận chữ ký nội bộ cho phiên bản hợp đồng{" "}
            {contractVersion || "mới nhất"}.
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-3">
          <div className="rounded-2xl border border-border/70 bg-card p-3">
            <canvas
              ref={canvasRef}
              width={PAD_WIDTH}
              height={PAD_HEIGHT}
              className="h-48 w-full rounded-xl border border-dashed border-border/80 bg-slate-50 touch-none"
              onPointerDown={drawStart}
              onPointerMove={drawMove}
              onPointerUp={drawEnd}
              onPointerLeave={drawEnd}
            />
            <p className="mt-2 text-xs text-muted-foreground">
              Ký bằng chuột hoặc cảm ứng. Chữ ký sẽ được lưu kèm thời điểm và
              metadata phiên ký.
            </p>
          </div>

          <div className="flex items-center justify-between gap-3 rounded-xl border border-border/70 bg-muted/30 p-3">
            <label className="flex items-start gap-2 text-sm text-foreground">
              <Checkbox
                checked={acceptedTerms}
                onCheckedChange={(checked) =>
                  setAcceptedTerms(Boolean(checked))
                }
              />
              <span>Tôi đã đọc, hiểu và đồng ý với điều khoản hợp đồng.</span>
            </label>

            <Button
              type="button"
              size="sm"
              variant="outline"
              onClick={clearSignature}
              className="gap-1.5"
            >
              <RotateCcw className="h-3.5 w-3.5" />
              Xóa chữ ký
            </Button>
          </div>
        </div>

        <DialogFooter className="gap-2">
          <Button variant="outline" onClick={() => onOpenChange?.(false)}>
            Hủy
          </Button>
          <Button onClick={handleConfirm} loading={loading} className="gap-1.5">
            <CheckCircle2 className="h-4 w-4" />
            Xác nhận ký
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
};

export default ContractSignModal;

import { memo } from "react";
import { Link } from "react-router-dom";
import {
  Clock,
  CheckCircle,
  Trophy,
  XCircle,
  UserX,
  ArrowRight,
  ChevronLeft,
  ChevronRight,
  AlertCircle,
  User,
} from "lucide-react";
import { Card, CardContent, CardHeader } from "@/components/ui/Card";
import { Button } from "@/components/ui/Button";
import { Badge } from "@/components/ui/badge";
import { Skeleton } from "@/components/ui/skeleton";
import { cn } from "@/lib/utils";
import { BOOKING_STATUS } from "@/constants/constants";

// ─── Helpers ────────────────────────────────────────────────────────────────

export const formatVND = (price) =>
  new Intl.NumberFormat("vi-VN", { style: "currency", currency: "VND" }).format(
    price || 0,
  );

export const formatDate = (date) =>
  date
    ? new Date(date).toLocaleDateString("vi-VN", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
      })
    : "—";

export const formatDateTime = (date) =>
  date
    ? new Date(date).toLocaleString("vi-VN", {
        day: "2-digit",
        month: "2-digit",
        year: "numeric",
        hour: "2-digit",
        minute: "2-digit",
      })
    : "—";

const WELCOME_PATTERN_STYLE = {
  backgroundImage:
    "radial-gradient(circle, rgba(15, 23, 42, 0.06) 1px, transparent 1px)",
  backgroundSize: "20px 20px",
};

const formatTrendValue = (trend) => {
  if (trend === undefined || trend === null || trend === "") return null;
  if (typeof trend === "number") {
    const sign = trend > 0 ? "+" : "";
    return `${sign}${trend}%`;
  }
  return String(trend);
};

// ─── Design Tokens ──────────────────────────────────────────────────────────

export const DESIGN = {
  card: "rounded-2xl border border-border/60 bg-card shadow-sm transition-all duration-300 dark:bg-zinc-950/70 dark:backdrop-blur-md",
  cardHover: "hover:shadow-md hover:-translate-y-0.5 active:scale-[0.995]",
  tabUnderlineTrigger:
    "h-9 px-3 text-xs rounded-none border-b-2 border-transparent data-[state=active]:border-primary data-[state=active]:bg-transparent data-[state=active]:text-primary",
  sectionHeader:
    "px-5 py-4 border-b border-border/60 flex items-center justify-between",
  iconBox: (color) =>
    cn(
      "rounded-xl p-3 flex items-center justify-center shrink-0",
      {
        emerald:
          "bg-emerald-100 text-emerald-600 dark:bg-emerald-950/50 dark:text-emerald-400",
        teal: "bg-teal-100 text-teal-600 dark:bg-teal-950/50 dark:text-teal-400",
        blue: "bg-blue-100 text-blue-600 dark:bg-blue-950/50 dark:text-blue-400",
        amber:
          "bg-amber-100 text-amber-600 dark:bg-amber-950/50 dark:text-amber-400",
        rose: "bg-rose-100 text-rose-600 dark:bg-rose-950/50 dark:text-rose-400",
        violet:
          "bg-violet-100 text-violet-600 dark:bg-violet-950/50 dark:text-violet-400",
        primary: "bg-primary/10 text-primary dark:bg-primary/20",
      }[color] || "bg-muted text-muted-foreground",
    ),
};

const SPARKLINE_BAR_CLASS = {
  emerald: "bg-emerald-500/80",
  teal: "bg-teal-500/80",
  blue: "bg-blue-500/80",
  amber: "bg-amber-500/80",
  rose: "bg-rose-500/80",
  violet: "bg-violet-500/80",
  primary: "bg-primary/80",
};

// ─── Status Config (Booking) ─────────────────────────────────────────────────

export const BOOKING_STATUS_CONFIG = {
  [BOOKING_STATUS.PENDING]: {
    label: "Chờ xác nhận",
    icon: Clock,
    className:
      "bg-amber-100 text-amber-700 border-amber-200 dark:bg-amber-950/40 dark:text-amber-400 dark:border-amber-800",
  },
  [BOOKING_STATUS.CONFIRMED]: {
    label: "Đã xác nhận",
    icon: CheckCircle,
    className:
      "bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-950/40 dark:text-blue-400 dark:border-blue-800",
  },
  [BOOKING_STATUS.COMPLETED]: {
    label: "Hoàn thành",
    icon: Trophy,
    className:
      "bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-950/40 dark:text-emerald-400 dark:border-emerald-800",
  },
  [BOOKING_STATUS.CANCELLED]: {
    label: "Đã hủy",
    icon: XCircle,
    className:
      "bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-950/40 dark:text-rose-400 dark:border-rose-800",
  },
  [BOOKING_STATUS.NO_SHOW]: {
    label: "Không đến",
    icon: UserX,
    className:
      "bg-gray-100 text-gray-600 border-gray-200 dark:bg-gray-800/40 dark:text-gray-400 dark:border-gray-700",
  },
};

// ─── StatusBadge ─────────────────────────────────────────────────────────────

export const StatusBadge = ({ status, className }) => {
  const cfg = BOOKING_STATUS_CONFIG[status];
  if (!cfg) return <Badge variant="outline">{status}</Badge>;
  const StatusIcon = cfg.icon;
  return (
    <span
      className={cn(
        "inline-flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium border",
        cfg.className,
        className,
      )}
    >
      <StatusIcon className="h-3.5 w-3.5 shrink-0" />
      {cfg.label}
    </span>
  );
};

// ─── WelcomeBanner ───────────────────────────────────────────────────────────

const WelcomeBannerBase = ({ name, role = "Chủ doanh nghiệp" }) => {
  const now = new Date();
  const dateStr = now.toLocaleDateString("vi-VN");
  const shortName = name || "Doanh nghiệp";
  const initials = shortName
    .split(" ")
    .filter(Boolean)
    .slice(0, 2)
    .map((part) => part[0]?.toUpperCase() || "")
    .join("");

  return (
    <div className="relative overflow-hidden rounded-2xl border border-border/60 bg-gradient-to-r from-primary/10 via-background to-background px-6 py-6 shadow-sm">
      <div
        className="pointer-events-none absolute inset-0 opacity-60"
        style={WELCOME_PATTERN_STYLE}
      />
      <div className="pointer-events-none absolute -top-14 -right-12 h-40 w-40 rounded-full bg-primary/10 blur-2xl" />
      <div className="relative z-10 flex items-center justify-between gap-4">
        <div className="flex min-w-0 items-center gap-4">
          <div className="flex h-12 w-12 items-center justify-center rounded-full border border-primary/20 bg-primary/10 text-primary">
            {initials ? (
              <span className="text-sm font-semibold tracking-wide">
                {initials}
              </span>
            ) : (
              <User className="h-5 w-5" />
            )}
          </div>
          <div className="min-w-0 space-y-1">
            <h1 className="text-2xl font-semibold tracking-tight text-foreground">
              Chào mừng, {shortName}!
            </h1>
            <p className="text-sm text-muted-foreground">
              {role} • Hôm nay là {dateStr}
            </p>
          </div>
        </div>

        <div className="hidden md:flex items-center gap-2">
          <div className="rounded-xl border border-border/60 bg-card/80 px-3 py-2 text-right shadow-sm">
            <p className="text-[10px] uppercase tracking-wide text-muted-foreground">
              Vai trò
            </p>
            <p className="text-xs font-semibold text-foreground truncate max-w-[130px]">
              {role}
            </p>
          </div>
          <div className="rounded-xl border border-border/60 bg-card/80 px-3 py-2 text-right shadow-sm">
            <p className="text-[10px] uppercase tracking-wide text-muted-foreground">
              Ngày
            </p>
            <p className="text-xs font-semibold text-foreground">{dateStr}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export const WelcomeBanner = memo(WelcomeBannerBase);
WelcomeBanner.displayName = "WelcomeBanner";

const MiniSparklineBase = ({ data, color = "primary" }) => {
  if (!Array.isArray(data) || data.length === 0) return null;

  const max = Math.max(...data, 1);
  const barClass = SPARKLINE_BAR_CLASS[color] || SPARKLINE_BAR_CLASS.primary;

  return (
    <div className="mt-3 flex h-10 items-end gap-1">
      {data.map((point, index) => {
        const heightPercent = Math.max(
          18,
          Math.min(100, Math.round((point / max) * 100)),
        );
        return (
          <div
            key={`${index}-${point}`}
            className={cn(
              "w-2 rounded-full transition-all duration-300",
              barClass,
            )}
            style={{ height: `${heightPercent}%` }}
          />
        );
      })}
    </div>
  );
};

const MiniSparkline = memo(MiniSparklineBase);
MiniSparkline.displayName = "MiniSparkline";

// ─── StatCard ─────────────────────────────────────────────────────────────────

export const StatCard = ({
  title,
  value,
  icon: _Icon,
  iconColor = "primary",
  trend,
  miniChart,
  description,
  href,
  loading,
}) => {
  if (loading) return <StatCardSkeleton />;

  const trendValue = formatTrendValue(trend);

  return (
    <Card className={cn(DESIGN.card, DESIGN.cardHover, "group")}>
      <CardHeader className="flex flex-row items-center justify-between space-y-0 p-5 pb-2">
        <div className={DESIGN.iconBox(iconColor)}>
          <_Icon className="h-5 w-5" />
        </div>
        {trendValue && (
          <Badge
            variant="secondary"
            className="rounded-lg border border-border/60 bg-muted/70 text-xs font-semibold"
          >
            {trendValue}
          </Badge>
        )}
      </CardHeader>
      <CardContent className="p-5 pt-0">
        <div className="min-w-0 space-y-1">
          <p className="truncate text-[32px] font-semibold leading-tight tracking-tighter text-foreground">
            {value}
          </p>
          <p className="text-sm text-muted-foreground">{title}</p>
          {description && (
            <p className="text-xs text-muted-foreground/90 leading-relaxed">
              {description}
            </p>
          )}
        </div>

        <MiniSparkline data={miniChart} color={iconColor} />

        {href && (
          <Link
            to={href}
            className="mt-3 inline-flex items-center gap-1 text-xs font-semibold text-muted-foreground transition-colors hover:text-foreground"
          >
            Xem chi tiết <ArrowRight className="h-3.5 w-3.5" />
          </Link>
        )}
      </CardContent>
    </Card>
  );
};

const SectionCardBase = ({
  title,
  titleIcon: TitleIcon,
  action,
  children,
  className,
  bodyClassName,
}) => (
  <Card className={cn(DESIGN.card, className)}>
    {title && (
      <div className={DESIGN.sectionHeader}>
        <div className="flex items-center gap-2">
          {TitleIcon && <TitleIcon className="h-4 w-4 text-muted-foreground" />}
          <h3 className="text-sm font-semibold text-foreground">{title}</h3>
        </div>
        {action && <div className="flex items-center gap-2">{action}</div>}
      </div>
    )}
    <CardContent className={cn("p-5", bodyClassName)}>{children}</CardContent>
  </Card>
);

export const SectionCard = memo(SectionCardBase);
SectionCard.displayName = "SectionCard";

const PageHeaderBase = ({ title, subtitle, badge, action }) => (
  <div className="flex flex-col gap-4 sm:flex-row sm:items-end sm:justify-between">
    <div className="space-y-1">
      <div className="flex flex-wrap items-center gap-2.5">
        <h1 className="text-2xl font-bold tracking-tight text-foreground">
          {title}
        </h1>
        {badge !== undefined && badge !== null && (
          <span className="rounded-full bg-muted px-2.5 py-0.5 text-xs font-semibold text-muted-foreground">
            {badge}
          </span>
        )}
      </div>
      {subtitle && (
        <p className="text-sm leading-relaxed text-muted-foreground">
          {subtitle}
        </p>
      )}
    </div>
    {action && <div className="flex shrink-0 items-center gap-2">{action}</div>}
  </div>
);

export const PageHeader = memo(PageHeaderBase);
PageHeader.displayName = "PageHeader";

const EmptyStateBase = ({ icon: _Icon = AlertCircle, message, action }) => (
  <div className="flex flex-col items-center justify-center gap-4 px-6 py-16 text-center">
    <div className="rounded-2xl bg-muted p-5">
      <_Icon className="h-9 w-9 text-muted-foreground" />
    </div>
    <p className="max-w-xs text-sm font-medium leading-relaxed text-muted-foreground">
      {message}
    </p>
    {action && <div className="mt-2">{action}</div>}
  </div>
);

export const EmptyState = memo(EmptyStateBase);
EmptyState.displayName = "EmptyState";

const LoadingStateBase = ({ message = "Đang tải dữ liệu..." }) => (
  <div className="flex flex-col items-center justify-center gap-3 py-16">
    <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
    <p className="text-sm text-muted-foreground">{message}</p>
  </div>
);

export const LoadingState = memo(LoadingStateBase);
LoadingState.displayName = "LoadingState";

const StatCardSkeletonBase = () => (
  <Card className={DESIGN.card}>
    <CardHeader className="flex flex-row items-center justify-between space-y-0 p-5 pb-2">
      <Skeleton className="h-12 w-12 rounded-xl" />
      <Skeleton className="h-6 w-16 rounded-lg" />
    </CardHeader>
    <CardContent className="space-y-2 p-5 pt-0">
      <Skeleton className="h-8 w-28" />
      <Skeleton className="h-4 w-24" />
      <div className="flex h-10 items-end gap-1 pt-1">
        {Array.from({ length: 8 }).map((_, idx) => (
          <Skeleton key={idx} className="h-full w-2 rounded-full" />
        ))}
      </div>
    </CardContent>
  </Card>
);

export const StatCardSkeleton = memo(StatCardSkeletonBase);
StatCardSkeleton.displayName = "StatCardSkeleton";

export const SectionCardSkeleton = ({ rows = 4 }) => (
  <Card className={DESIGN.card}>
    <div className={DESIGN.sectionHeader}>
      <Skeleton className="h-4 w-36" />
    </div>
    <CardContent className="space-y-3 p-5">
      {Array.from({ length: rows }).map((_, i) => (
        <div key={i} className="flex items-center justify-between">
          <Skeleton className="h-4 w-1/3" />
          <Skeleton className="h-4 w-1/4" />
        </div>
      ))}
    </CardContent>
  </Card>
);

export const TableRowSkeleton = ({ cols = 4 }) => (
  <div className="flex items-center gap-4 border-b border-border/50 px-5 py-4">
    {Array.from({ length: cols }).map((_, i) => (
      <Skeleton key={i} className="h-4 flex-1" />
    ))}
  </div>
);

// ─── Pagination ───────────────────────────────────────────────────────────────

export const PageNav = ({ page, totalPages, total, onPageChange }) => {
  if (totalPages <= 1) return null;

  const pages = Array.from({ length: totalPages }, (_, i) => i + 1)
    .filter((p) => p === 1 || p === totalPages || Math.abs(p - page) <= 1)
    .reduce((acc, p, idx, arr) => {
      if (idx > 0 && p - arr[idx - 1] > 1) acc.push("...");
      acc.push(p);
      return acc;
    }, []);

  return (
    <div className="flex items-center justify-between py-3 px-1">
      {total !== undefined && (
        <p className="text-xs text-muted-foreground">
          Trang <span className="font-semibold text-foreground">{page}</span> /{" "}
          {totalPages}
          {total > 0 && <> · {total} kết quả</>}
        </p>
      )}
      <div className="flex items-center gap-1 ml-auto">
        <Button
          variant="outline"
          size="sm"
          className="h-8 w-8 p-0"
          onClick={() => onPageChange(Math.max(1, page - 1))}
          disabled={page === 1}
        >
          <ChevronLeft className="h-4 w-4" />
        </Button>
        {pages.map((p, idx) =>
          p === "..." ? (
            <span
              key={`e-${idx}`}
              className="px-2 text-muted-foreground text-xs"
            >
              …
            </span>
          ) : (
            <Button
              key={p}
              variant={p === page ? "default" : "outline"}
              size="sm"
              className="h-8 w-8 p-0 text-xs"
              onClick={() => onPageChange(p)}
            >
              {p}
            </Button>
          ),
        )}
        <Button
          variant="outline"
          size="sm"
          className="h-8 w-8 p-0"
          onClick={() => onPageChange(Math.min(totalPages, page + 1))}
          disabled={page === totalPages}
        >
          <ChevronRight className="h-4 w-4" />
        </Button>
      </div>
    </div>
  );
};

// ─── StatusProgress (cho dashboard / revenue) ─────────────────────────────────

export const StatusProgressRow = ({ label, count, total, colorClass }) => {
  const pct = total > 0 ? (count / total) * 100 : 0;
  return (
    <div className="space-y-1.5">
      <div className="flex items-center justify-between text-xs">
        <span className="font-medium text-foreground">{label}</span>
        <span className="text-muted-foreground">
          {count} <span className="opacity-60">({pct.toFixed(0)}%)</span>
        </span>
      </div>
      <div className="h-2 rounded-full bg-muted overflow-hidden">
        <div
          className={cn(
            "h-full rounded-full transition-all duration-700",
            colorClass,
          )}
          style={{ width: `${Math.max(pct, 0)}%` }}
        />
      </div>
    </div>
  );
};

import { useState, useEffect } from "react";
import { X, Search } from "lucide-react";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Label } from "@/components/ui/Label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import useCategoryStore from "@/stores/categoryStore";
import { useToast } from "@/hooks/use-toast";
import {
  CATEGORY_ICON_MAP,
  CATEGORY_ICON_PRESETS,
  CATEGORY_COLOR_PRESETS,
} from "@/constants/categoryConstants";

/**
 * CATEGORY FORM DIALOG
 * Form tạo/sửa danh mục
 */

export default function CategoryFormDialog({
  open,
  onClose,
  category,
  parentCategory,
}) {
  const { createCategory, updateCategory, fetchCategories } =
    useCategoryStore();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [iconSearch, setIconSearch] = useState("");

  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    icon: "",
    color: "#3B82F6",
    description: "",
    parentId: null,
    order: 0,
  });

  useEffect(() => {
    if (category) {
      // Edit mode
      setFormData({
        name: category.name || "",
        slug: category.slug || "",
        icon: category.icon || "",
        color: category.color || "#3B82F6",
        description: category.description || "",
        parentId: category.parentId || null,
        order: category.order || 0,
      });
    } else if (parentCategory) {
      // Add child mode
      setFormData({
        name: "",
        slug: "",
        icon: "",
        color: "#3B82F6",
        description: "",
        parentId: parentCategory.id,
        order: 0,
      });
    } else {
      // Add root mode
      setFormData({
        name: "",
        slug: "",
        icon: "",
        color: "#3B82F6",
        description: "",
        parentId: null,
        order: 0,
      });
    }
  }, [category, parentCategory, open]);

  const handleChange = (field, value) => {
    setFormData((prev) => {
      const updated = { ...prev, [field]: value };

      // Auto-generate slug from name
      if (field === "name" && !category) {
        updated.slug = value
          .toLowerCase()
          .normalize("NFD")
          .replace(/[\u0300-\u036f]/g, "")
          .replace(/đ/g, "d")
          .replace(/[^a-z0-9\s-]/g, "")
          .trim()
          .replace(/\s+/g, "-");
      }

      return updated;
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      if (category) {
        await updateCategory(category.id, formData);
        toast({
          title: "Thành công",
          description: "Cập nhật danh mục thành công",
        });
      } else {
        await createCategory(formData);
        toast({
          title: "Thành công",
          description: "Tạo danh mục thành công",
        });
      }
      await fetchCategories();
      onClose();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Lỗi",
        description: error.response?.data?.message || error.message,
      });
    } finally {
      setLoading(false);
    }
  };

  const filteredIcons = CATEGORY_ICON_PRESETS.filter((icon) =>
    icon.toLowerCase().includes(iconSearch.toLowerCase()),
  );

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto rounded-none border border-black p-0 shadow-hard">
        <DialogHeader className="bg-black text-white p-6 border-b border-white/20">
          <DialogTitle className="text-xl font-black uppercase tracking-tight flex items-center justify-between">
            <span>
              {category
                ? "CHỈNH SỬA DANH MỤC"
                : parentCategory
                  ? "THÊM DANH MỤC CON"
                  : "TẠO DANH MỤC GỐC"}
            </span>
            <span className="text-[10px] font-mono bg-white text-black px-2 py-0.5">
              {category ? category.id.substring(0, 8) : "NEW"}
            </span>
          </DialogTitle>
          <DialogDescription className="text-gray-400 font-mono text-xs uppercase tracking-wider">
            {parentCategory
              ? `DIRECTORY PARENT: ${parentCategory.name}`
              : "ROOT DIRECTORY SYSTEM"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="p-6 space-y-6 bg-white">
          {/* Tên & Slug */}
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <Label
                htmlFor="name"
                className="uppercase font-bold text-xs tracking-wider"
              >
                TÊN DANH MỤC <span className="text-red-500">*</span>
              </Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => handleChange("name", e.target.value)}
                placeholder="VD: TRÀ SỮA..."
                required
                className="rounded-none border-black font-mono text-sm focus-visible:ring-0 focus-visible:border-primary border-b-2 bg-gray-50 h-10"
              />
            </div>
            <div className="space-y-2">
              <Label
                htmlFor="slug"
                className="uppercase font-bold text-xs tracking-wider"
              >
                SLUG (URL) <span className="text-red-500">*</span>
              </Label>
              <Input
                id="slug"
                value={formData.slug}
                onChange={(e) => handleChange("slug", e.target.value)}
                placeholder="vd: tra-sua"
                required
                className="rounded-none border-black font-mono text-sm focus-visible:ring-0 bg-gray-50 h-10"
              />
            </div>
          </div>

          {/* Icon Picker */}
          <div className="space-y-3">
            <div className="flex justify-between items-center border-b border-black pb-2">
              <Label className="uppercase font-bold text-xs tracking-wider">
                ICON HIỂN THỊ
              </Label>
              <div className="flex items-center gap-2">
                <Search className="w-3 h-3" />
                <Input
                  placeholder="SEARCH ICON..."
                  value={iconSearch}
                  onChange={(e) => setIconSearch(e.target.value)}
                  className="h-6 w-32 rounded-none border-none border-b border-gray-200 text-xs font-mono uppercase bg-transparent p-0 focus-visible:ring-0"
                />
              </div>
            </div>

            <div className="grid grid-cols-6 sm:grid-cols-8 gap-2 max-h-[160px] overflow-y-auto p-2 border border-black bg-gray-50 scrollbar-thin">
              {filteredIcons.map((iconName) => {
                const IconComponent = CATEGORY_ICON_MAP[iconName];
                if (!IconComponent) return null;

                const isSelected = formData.icon === iconName;

                return (
                  <button
                    key={iconName}
                    type="button"
                    className={`
                        aspect-square flex items-center justify-center border transition-all
                        ${
                          isSelected
                            ? "bg-black text-white border-black shadow-none scale-90"
                            : "bg-white text-gray-500 border-gray-200 hover:border-black hover:text-black hover:shadow-hard"
                        }
                      `}
                    onClick={() => handleChange("icon", iconName)}
                    title={iconName}
                  >
                    <IconComponent className="h-5 w-5" />
                  </button>
                );
              })}
            </div>
          </div>

          {/* Color & Order */}
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <Label className="uppercase font-bold text-xs tracking-wider">
                MÃ MÀU
              </Label>
              <div className="flex items-center gap-2">
                <div
                  className="w-10 h-10 border border-black relative"
                  style={{ backgroundColor: formData.color }}
                >
                  <Input
                    type="color"
                    value={formData.color}
                    onChange={(e) => handleChange("color", e.target.value)}
                    className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                  />
                </div>
                <Input
                  value={formData.color}
                  onChange={(e) => handleChange("color", e.target.value)}
                  className="flex-1 rounded-none border-black font-mono uppercase focus-visible:ring-0"
                />
              </div>
            </div>

            <div className="space-y-2">
              <Label
                htmlFor="order"
                className="uppercase font-bold text-xs tracking-wider"
              >
                THỨ TỰ (PRIORITY)
              </Label>
              <Input
                id="order"
                type="number"
                value={formData.order}
                onChange={(e) =>
                  handleChange("order", parseInt(e.target.value))
                }
                min="0"
                className="rounded-none border-black font-mono focus-visible:ring-0"
              />
            </div>
          </div>

          {/* Mô tả */}
          <div className="space-y-2">
            <Label
              htmlFor="description"
              className="uppercase font-bold text-xs tracking-wider"
            >
              MÔ TẢ NGẮN
            </Label>
            <Textarea
              id="description"
              value={formData.description}
              onChange={(e) => handleChange("description", e.target.value)}
              placeholder="CHI TIẾT..."
              rows={3}
              className="rounded-none border-black font-mono focus-visible:ring-0 bg-gray-50"
            />
          </div>

          <DialogFooter className="border-t border-black pt-6 gap-3">
            <Button
              type="button"
              variant="outline"
              onClick={onClose}
              disabled={loading}
              className="rounded-none border-black hover:bg-gray-200 font-mono uppercase"
            >
              HỦY BỎ
            </Button>
            <Button
              type="submit"
              disabled={loading}
              className="rounded-none bg-black text-white hover:bg-primary hover:text-black hover:shadow-hard font-bold uppercase transition-all"
            >
              {loading
                ? "ĐANG XỬ LÝ..."
                : category
                  ? "LƯU THAY ĐỔI"
                  : "TẠO DANH MỤC"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { locationService } from "@/apis/locationService";

/**
 * ProvinceDistrictSelect Component
 *
 * Component chọn tỉnh/thành phố và phường/xã cho địa chỉ người dùng.
 * Sử dụng API: https://34tinhthanh.com/api
 *
 * Lưu ý: API mới (2025) trả về 2 cấp:
 * - Level 1: Province (34 tỉnh/thành sau sát nhập)
 * - Level 2: Ward (bao gồm cả quận/huyện và phường/xã)
 *
 * Do đó, dropdown "Quận/Huyện/Phường/Xã" sẽ hiển thị tất cả đơn vị hành chính
 * cấp dưới của tỉnh/thành phố đã chọn.
 */

const ProvinceDistrictSelect = ({
  provinceCode,
  districtCode,
  onProvinceChange,
  onDistrictChange,
  errors = {},
}) => {
  const [provinces, setProvinces] = useState([]);
  const [districts, setDistricts] = useState([]);
  const [loadingProvinces, setLoadingProvinces] = useState(true);
  const [loadingDistricts, setLoadingDistricts] = useState(false);

  // Load provinces on mount
  useEffect(() => {
    const fetchProvinces = async () => {
      try {
        const data = await locationService.getAllProvinces();
        setProvinces(data);
      } catch (error) {
        console.error("Failed to load provinces:", error);
      } finally {
        setLoadingProvinces(false);
      }
    };

    fetchProvinces();
  }, []);

  // Load districts when province changes
  useEffect(() => {
    if (!provinceCode) {
      setDistricts([]);
      return;
    }

    const fetchDistricts = async () => {
      setLoadingDistricts(true);
      try {
        // API mới trả về wards (bao gồm cả quận/huyện và phường/xã)
        const data = await locationService.getWardsByProvince(provinceCode);
        setDistricts(data);
      } catch (error) {
        console.error("Failed to load districts:", error);
      } finally {
        setLoadingDistricts(false);
      }
    };

    fetchDistricts();
  }, [provinceCode]);

  const handleProvinceChange = (e) => {
    const newProvinceCode = e.target.value;
    onProvinceChange(newProvinceCode);
    // Reset district when province changes
    onDistrictChange("");
  };

  const selectClassName =
    "w-full py-2.5 pl-10 pr-8 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl text-sm text-slate-700 dark:text-slate-300 focus:ring-blue-600 focus:border-blue-600 cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors appearance-none disabled:opacity-50 disabled:cursor-not-allowed";

  return (
    <div className="space-y-4">
      {/* Province Select */}
      <div>
        <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
          Tỉnh/Thành phố
        </label>
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none z-10">
            <span className="material-icons-round text-lg">location_city</span>
          </span>
          <select
            id="provinceCode"
            value={provinceCode || ""}
            onChange={handleProvinceChange}
            disabled={loadingProvinces}
            className={selectClassName}
          >
            <option value="">
              {loadingProvinces ? "Đang tải..." : "-- Chọn tỉnh/thành phố --"}
            </option>
            {provinces.map((province) => (
              <option
                key={province.province_code}
                value={province.province_code}
              >
                {province.name}
              </option>
            ))}
          </select>
          <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
            <span className="material-icons-round text-lg">expand_more</span>
          </span>
        </div>
        {errors.provinceCode && (
          <p className="text-sm text-red-500 mt-1 flex items-center gap-1">
            <span className="material-icons-round text-sm">error</span>
            {errors.provinceCode}
          </p>
        )}
      </div>

      {/* District Select */}
      <div>
        <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-2">
          Quận/Huyện/Phường/Xã
        </label>
        <div className="relative">
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none z-10">
            <span className="material-icons-round text-lg">map</span>
          </span>
          <select
            id="districtCode"
            value={districtCode || ""}
            onChange={(e) => onDistrictChange(e.target.value)}
            disabled={
              !provinceCode || loadingDistricts || districts.length === 0
            }
            className={selectClassName}
          >
            <option value="">
              {loadingDistricts
                ? "Đang tải..."
                : !provinceCode
                ? "Vui lòng chọn tỉnh/thành phố trước"
                : "-- Chọn quận/huyện/phường/xã --"}
            </option>
            {districts.map((district) => (
              <option key={district.ward_code} value={district.ward_code}>
                {district.ward_name}
              </option>
            ))}
          </select>
          <span className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none">
            <span className="material-icons-round text-lg">expand_more</span>
          </span>
        </div>
        {errors.districtCode && (
          <p className="text-sm text-red-500 mt-1 flex items-center gap-1">
            <span className="material-icons-round text-sm">error</span>
            {errors.districtCode}
          </p>
        )}
      </div>
    </div>
  );
};

export default ProvinceDistrictSelect;

