source:
import { useState, useEffect } from "react";
import { DollarSign } from "lucide-react";
import { Input } from "@/components/ui/Input";
import { Button } from "@/components/ui/Button";
import { Slider } from "@/components/ui/slider";
import { cn } from "@/lib/utils";
import { PRICE_RANGES } from "@/constants/placeConstants";

/**
 * PRICE RANGE SLIDER V2
 * Component để chọn mức giá với thanh slider interactive
 * Updated: Vietnamese Denomination Support (suffix .000)
 */

const PriceRangeSlider = ({
  priceRange,
  priceFrom,
  priceTo,
  onChange,
  error,
}) => {
  const [showCustom, setShowCustom] = useState(!!priceFrom || !!priceTo);

  // Slider range: 0đ to 2,000,000đ with 10,000đ steps
  const MAX_PRICE = 2000000;

  // Convert prices to slider values
  const [sliderValues, setSliderValues] = useState([
    priceFrom || 0,
    priceTo || 500000,
  ]);

  // Update slider visual when props change externally
  useEffect(() => {
    if (priceFrom !== undefined && priceTo !== undefined) {
      setSliderValues([priceFrom || 0, priceTo || 500000]);
    }
  }, [priceFrom, priceTo]);

  const handleRangeChange = (range) => {
    onChange({ priceRange: range, priceFrom: 0, priceTo: 0 }); // Reset custom amounts
    setShowCustom(false);
  };

  const handleSliderChange = (values) => {
    setSliderValues(values);
    onChange({
      priceRange: priceRange || "MODERATE",
      priceFrom: values[0],
      priceTo: values[1],
    });
  };

  const handleInputChange = (field, thousandValue) => {
    // User inputs 50 -> means 50,000
    const realValue = thousandValue ? parseInt(thousandValue) * 1000 : 0;

    // Ensure logical constraint
    let newValues;
    if (field === "priceFrom") {
      newValues = [realValue, Math.max(realValue, sliderValues[1])];
    } else {
      newValues = [Math.min(realValue, sliderValues[0]), realValue];
    }

    setSliderValues(newValues);
    onChange({
      priceRange: priceRange || "MODERATE",
      priceFrom: newValues[0],
      priceTo: newValues[1],
    });
  };

  const QUICK_SUGGESTIONS = [
    { label: "20k", val: 20 },
    { label: "50k", val: 50 },
    { label: "100k", val: 100 },
    { label: "200k", val: 200 },
    { label: "500k", val: 500 },
    { label: "1tr", val: 1000 },
  ];

  const setManualValue = (field, kValue) => {
    handleInputChange(field, kValue);
  };

  return (
    <div className="space-y-6">
      <div>
        <label className="text-xs font-bold uppercase tracking-wider mb-3 block">
          MỨC GIÁ DỰ KIẾN
        </label>

        {/* Price Range Quick Select */}
        <div className="grid grid-cols-2 sm:grid-cols-5 gap-0 border border-black bg-white">
          {PRICE_RANGES.map((range) => (
            <button
              key={range.value}
              type="button"
              onClick={() => handleRangeChange(range.value)}
              className={cn(
                "p-4 text-center transition-all border-r last:border-r-0 border-black hover:bg-black hover:text-white group relative",
                priceRange === range.value && !showCustom
                  ? "bg-black text-white"
                  : "bg-white text-black",
              )}
            >
              <div className="text-sm font-mono font-bold mb-1">
                {range.icon}
              </div>
              <div className="font-bold text-[10px] uppercase tracking-wider mb-1">
                {range.label}
              </div>
              <div
                className={cn(
                  "text-[10px] font-mono opacity-60",
                  priceRange === range.value && !showCustom
                    ? "text-gray-300"
                    : "text-gray-500 group-hover:text-gray-300",
                )}
              >
                {range.description}
              </div>

              {/* Active Indicator */}
              {priceRange === range.value && !showCustom && (
                <div className="absolute top-0 right-0 w-2 h-2 bg-white"></div>
              )}
            </button>
          ))}
        </div>

        {error && (
          <p className="text-sm text-red-500 mt-2 font-mono uppercase">
            ERROR: {error}
          </p>
        )}
      </div>

      {/* Custom Price Button */}
      <div className="space-y-4">
        <Button
          type="button"
          variant={showCustom ? "default" : "outline"}
          onClick={() => setShowCustom(!showCustom)}
          className={cn(
            "w-full rounded-none border border-black font-mono text-xs uppercase tracking-widest h-10 transition-all",
            showCustom
              ? "bg-black text-white hover:bg-black/90"
              : "bg-white text-black hover:bg-gray-100",
          )}
        >
          {showCustom
            ? "[-] ẨN TÙY CHỈNH GIÁ"
            : "[+] CHỌN KHOẢNG GIÁ TÙY CHỈNH"}
        </Button>

        {showCustom && (
          <div className="p-6 border border-black bg-gray-50 animate-in slide-in-from-top-2">
            {/* Inputs */}
            <div className="flex items-center gap-6 mb-6">
              <div className="flex-1 space-y-2">
                <label className="text-[10px] uppercase font-bold text-gray-500 flex justify-between">
                  <span>TỐI THIỂU (Min)</span>
                  <span className="text-black font-mono">
                    {sliderValues[0].toLocaleString("vi-VN")} đ
                  </span>
                </label>
                <div className="relative">
                  <Input
                    type="number"
                    value={sliderValues[0] > 0 ? sliderValues[0] / 1000 : ""}
                    placeholder="0"
                    onChange={(e) =>
                      handleInputChange("priceFrom", e.target.value)
                    }
                    className="rounded-none border-black font-mono text-right pr-12 text-lg h-12 bg-white"
                  />
                  <span className="absolute right-3 top-3 text-gray-400 font-mono text-base pointer-events-none select-none bg-white pl-1">
                    .000
                  </span>
                </div>
                {/* Quick Set Min */}
                <div className="flex gap-1 flex-wrap">
                  {QUICK_SUGGESTIONS.slice(0, 3).map((opt) => (
                    <button
                      key={`min-${opt.val}`}
                      type="button"
                      onClick={() => setManualValue("priceFrom", opt.val)}
                      className="px-2 py-1 bg-gray-200 hover:bg-black hover:text-white text-[10px] font-mono transition-colors"
                    >
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>

              <div className="font-mono pt-4 text-gray-400">-</div>

              <div className="flex-1 space-y-2">
                <label className="text-[10px] uppercase font-bold text-gray-500 flex justify-between">
                  <span>TỐI ĐA (Max)</span>
                  <span className="text-black font-mono">
                    {sliderValues[1].toLocaleString("vi-VN")} đ
                  </span>
                </label>
                <div className="relative">
                  <Input
                    type="number"
                    value={sliderValues[1] > 0 ? sliderValues[1] / 1000 : ""}
                    placeholder="0"
                    onChange={(e) =>
                      handleInputChange("priceTo", e.target.value)
                    }
                    className="rounded-none border-black font-mono text-right pr-12 text-lg h-12 bg-white"
                  />
                  <span className="absolute right-3 top-3 text-gray-400 font-mono text-base pointer-events-none select-none bg-white pl-1">
                    .000
                  </span>
                </div>
                {/* Quick Set Max */}
                <div className="flex gap-1 flex-wrap">
                  {QUICK_SUGGESTIONS.slice(1).map((opt) => (
                    <button
                      key={`max-${opt.val}`}
                      type="button"
                      onClick={() => setManualValue("priceTo", opt.val)}
                      className="px-2 py-1 bg-gray-200 hover:bg-black hover:text-white text-[10px] font-mono transition-colors"
                    >
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            <Slider
              value={sliderValues}
              max={MAX_PRICE}
              step={10000}
              minStepsBetweenThumbs={1}
              onValueChange={handleSliderChange}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default PriceRangeSlider;

import { useState, useEffect } from "react";
import ArrowRight from "lucide-react/dist/esm/icons/arrow-right";
import Loader2 from "lucide-react/dist/esm/icons/loader-2";
import MapPin from "lucide-react/dist/esm/icons/map-pin";
import Globe from "lucide-react/dist/esm/icons/globe";
import FileText from "lucide-react/dist/esm/icons/file-text";
import Type from "lucide-react/dist/esm/icons/type";
import AnimatedIcon from "@/components/ui/animated-icon";
import usePlaceStore from "@/stores/placeStore";
import * as districtService from "@/apis/districtService";
import * as wardService from "@/apis/wardService";
import {
  Button,
  Input,
  Label,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui";
import { Textarea } from "@/components/ui/textarea";
import CategorySelector from "./CategorySelector";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";

/**
 * STEP 1: BASIC INFO
 * Technical Industrial Minimalism Redesign
 */

const StepBasicInfo = () => {
  const { toast } = useToast();
  const { wizardData, updateWizardData, nextStep, loading, checkSlugExists } =
    usePlaceStore();

  const [districts, setDistricts] = useState([]);
  const [wards, setWards] = useState([]);
  const [loadingDistricts, setLoadingDistricts] = useState(false);
  const [loadingWards, setLoadingWards] = useState(false);
  const [errors, setErrors] = useState({});
  const [checkingSlug, setCheckingSlug] = useState(false);

  // Load districts on mount
  useEffect(() => {
    loadDistricts();
  }, []);

  // Load wards when district changes
  useEffect(() => {
    if (wizardData.districtId) {
      loadWards(wizardData.districtId);
    } else {
      setWards([]);
      // Only reset wardId if it's currently set to avoid infinite loop
      if (wizardData.wardId !== null) {
        updateWizardData({ wardId: null });
      }
    }
     
  }, [wizardData.districtId, wizardData.wardId]);

  const loadDistricts = async () => {
    setLoadingDistricts(true);
    try {
      const response = await districtService.getAllDistricts();
      setDistricts(response.data || []);
    } catch {
      toast({
        variant: "destructive",
        title: "LỖI HỆ THỐNG",
        description: "Không thể tải dữ liệu quận/huyện.",
      });
    } finally {
      setLoadingDistricts(false);
    }
  };

  const loadWards = async (districtId) => {
    setLoadingWards(true);
    try {
      const response = await wardService.getWardsByDistrict(districtId);
      setWards(response.data || []);
    } catch {
      toast({
        variant: "destructive",
        title: "LỖI HỆ THỐNG",
        description: "Không thể tải dữ liệu phường/xã.",
      });
      setWards([]);
    } finally {
      setLoadingWards(false);
    }
  };

  // Auto-generate slug from name
  const generateSlug = (name) => {
    return name
      .toLowerCase()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "") // Remove accents
      .replace(/đ/g, "d")
      .replace(/[^a-z0-9\s-]/g, "")
      .replace(/\s+/g, "-")
      .replace(/-+/g, "-")
      .trim();
  };

  const handleNameChange = (e) => {
    const name = e.target.value;

    // Auto-generate slug if not manually edited
    const shouldUpdateSlug =
      !wizardData.slug || generateSlug(wizardData.name) === wizardData.slug;

    if (shouldUpdateSlug) {
      const newSlug = generateSlug(name);
      updateWizardData({ name, slug: newSlug });
    } else {
      updateWizardData({ name });
    }
  };

  const handleSlugChange = async (e) => {
    const slug = e.target.value;
    updateWizardData({ slug });

    // Check if slug exists (debounced)
    if (slug && slug.length >= 3) {
      setCheckingSlug(true);
      try {
        const exists = await checkSlugExists(slug);
        setErrors((prev) => ({
          ...prev,
          slug: exists ? "SLUG ĐÃ TỒN TẠI" : null,
        }));
      } catch {
        // Ignore check errors
      } finally {
        setCheckingSlug(false);
      }
    }
  };

  const validate = () => {
    const newErrors = {};

    if (!wizardData.name?.trim()) {
      newErrors.name = "VUI LÒNG NHẬP TÊN ĐỊA ĐIỂM";
    }

    if (!wizardData.slug?.trim()) {
      newErrors.slug = "VUI LÒNG NHẬP SLUG";
    }

    if (!wizardData.categoryId) {
      newErrors.categoryId = "VUI LÒNG CHỌN DANH MỤC";
    }

    if (!wizardData.districtId) {
      newErrors.districtId = "VUI LÒNG CHỌN QUẬN/HUYỆN";
    }

    if (!wizardData.address?.trim()) {
      newErrors.address = "VUI LÒNG NHẬP ĐỊA CHỈ";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleNext = () => {
    if (validate()) {
      nextStep();
    } else {
      toast({
        variant: "destructive",
        title: "DỮ LIỆU KHÔNG HỢP LỆ",
        description: "Vui lòng kiểm tra các trường bắt buộc màu đỏ.",
      });
    }
  };

  // Shared Styles
  const labelStyle =
    "text-xs font-bold uppercase tracking-widest text-slate-500 mb-1.5 font-mono block";
  const inputStyle =
    "rounded-none border-black focus:ring-1 focus:ring-black font-mono text-sm";
  const errorStyle =
    "text-xs text-red-600 font-bold uppercase mt-1 font-mono flex items-center gap-1";

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-500 pb-12">
      {/* Category Section - Full Width */}
      <section className="space-y-4">
        <CategorySelector
          value={wizardData.categoryId}
          onChange={(categoryId) => updateWizardData({ categoryId })}
          error={errors.categoryId}
        />
      </section>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-start">
        {/* Left Column: Basic Details */}
        <div className="space-y-6">
          <div className="flex items-center gap-2 border-b-2 border-black pb-2 mb-4">
            <Type className="w-5 h-5" />
            <h3 className="text-lg font-black uppercase tracking-widest">
              THÔNG TIN CHUNG
            </h3>
          </div>

          <div className="space-y-1">
            <label htmlFor="name" className={labelStyle}>
              TÊN ĐỊA ĐIỂM <span className="text-red-600">*</span>
            </label>
            <div className="relative group">
              <Input
                id="name"
                placeholder="VD: CAFE SÔNG HẬU"
                value={wizardData.name}
                onChange={handleNameChange}
                className={cn(
                  inputStyle,
                  errors.name && "border-red-600 bg-red-50",
                )}
              />
            </div>
            {errors.name && <p className={errorStyle}>⚠ {errors.name}</p>}
          </div>

          <div className="space-y-1">
            <label htmlFor="slug" className={labelStyle}>
              ĐƯỜNG DẪN (SLUG) <span className="text-red-600">*</span>
            </label>
            <div className="relative">
              <Input
                id="slug"
                placeholder="quan-cafe-song-hau"
                value={wizardData.slug}
                onChange={handleSlugChange}
                className={cn(
                  inputStyle,
                  "pr-10 lowercase",
                  errors.slug && "border-red-600 bg-red-50",
                )}
              />
              <div className="absolute right-3 top-2.5">
                {checkingSlug ? (
                  <Loader2 className="h-4 w-4 animate-spin text-black" />
                ) : (
                  <Globe className="h-4 w-4 text-slate-400" />
                )}
              </div>
            </div>
            {errors.slug && <p className={errorStyle}>⚠ {errors.slug}</p>}
            <div className="text-[10px] text-slate-500 font-mono mt-1 w-full truncate border border-dashed border-slate-300 p-1 bg-slate-50">
              didaugio.com/place/{wizardData.slug || "slug-cua-ban"}
            </div>
          </div>

          <div className="space-y-1">
            <label htmlFor="shortDescription" className={labelStyle}>
              MÔ TẢ NGẮN
            </label>
            <Textarea
              id="shortDescription"
              placeholder="MÔ TẢ NGẮN GỌN CHO THẺ DANH SÁCH..."
              rows={4}
              value={wizardData.shortDescription}
              onChange={(e) =>
                updateWizardData({ shortDescription: e.target.value })
              }
              maxLength={200}
              className={cn(inputStyle, "resize-none min-h-[120px]")}
            />
            <div className="flex justify-end border-t border-black/10">
              <span className="text-[10px] font-mono font-bold text-slate-400">
                {wizardData.shortDescription?.length || 0}/200 KÝ TỰ
              </span>
            </div>
          </div>
        </div>

        {/* Right Column: Location Details */}
        <div className="space-y-6">
          <div className="flex items-center gap-2 border-b-2 border-black pb-2 mb-4">
            <MapPin className="w-5 h-5" />
            <h3 className="text-lg font-black uppercase tracking-widest">
              THÔNG TIN VỊ TRÍ
            </h3>
          </div>

          <div className="p-1 border border-black bg-white shadow-[4px_4px_0px_0px_rgba(0,0,0,1)]">
            <div className="bg-slate-50 border border-slate-200 p-4 space-y-5">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label htmlFor="district" className={labelStyle}>
                    QUẬN/HUYỆN <span className="text-red-600">*</span>
                  </label>
                  <Select
                    value={
                      wizardData.districtId
                        ? wizardData.districtId.toString()
                        : ""
                    }
                    onValueChange={(val) =>
                      updateWizardData({ districtId: parseInt(val) })
                    }
                    disabled={loadingDistricts}
                  >
                    <SelectTrigger
                      className={cn(
                        inputStyle,
                        errors.districtId && "border-red-600 bg-red-50",
                      )}
                    >
                      {loadingDistricts ? (
                        <div className="flex items-center gap-2">
                          <Loader2 className="h-3 w-3 animate-spin" />
                          <span className="text-xs">ĐANG TẢI...</span>
                        </div>
                      ) : (
                        <SelectValue placeholder="CHỌN QUẬN" />
                      )}
                    </SelectTrigger>
                    <SelectContent className="rounded-none border-black">
                      {districts.map((district) => (
                        <SelectItem
                          key={district.id}
                          value={district.id.toString()}
                          className="font-mono text-xs focus:bg-black focus:text-white rounded-none"
                        >
                          {district.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                  {errors.districtId && <p className={errorStyle}>BẮT BUỘC</p>}
                </div>

                <div className="space-y-1">
                  <label htmlFor="ward" className={labelStyle}>
                    PHƯỜNG/XÃ
                  </label>
                  <Select
                    value={
                      wizardData.wardId ? wizardData.wardId.toString() : ""
                    }
                    onValueChange={(val) =>
                      updateWizardData({ wardId: parseInt(val) })
                    }
                    disabled={!wizardData.districtId || loadingWards}
                  >
                    <SelectTrigger className={inputStyle}>
                      {loadingWards ? (
                        <div className="flex items-center gap-2">
                          <Loader2 className="h-3 w-3 animate-spin" />
                          <span className="text-xs">ĐANG TẢI...</span>
                        </div>
                      ) : (
                        <SelectValue placeholder="CHỌN PHƯỜNG" />
                      )}
                    </SelectTrigger>
                    <SelectContent className="rounded-none border-black h-[200px]">
                      {wards.map((ward) => (
                        <SelectItem
                          key={ward.id}
                          value={ward.id.toString()}
                          className="font-mono text-xs focus:bg-black focus:text-white rounded-none"
                        >
                          {ward.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="space-y-1">
                <label htmlFor="address" className={labelStyle}>
                  SỐ NHÀ, TÊN ĐƯỜNG <span className="text-red-600">*</span>
                </label>
                <Input
                  id="address"
                  placeholder="VD: 123 Nguyễn Văn Linh"
                  value={wizardData.address}
                  onChange={(e) =>
                    updateWizardData({ address: e.target.value })
                  }
                  className={cn(
                    inputStyle,
                    errors.address && "border-red-600 bg-red-50",
                  )}
                />
                {errors.address && (
                  <p className={errorStyle}>⚠ {errors.address}</p>
                )}
              </div>
            </div>
            <div className="bg-black text-white p-2 text-[10px] font-mono text-center uppercase">
              Đảm bảo chính xác để hiển thị trên bản đồ
            </div>
          </div>
        </div>
      </div>

      {/* Actions */}
      <div className="flex justify-end pt-6 border-t-2 border-black border-dashed mt-8">
        <Button
          onClick={handleNext}
          disabled={loading}
          className="rounded-none border border-black bg-black text-white shadow-[4px_4px_0px_0px_rgba(0,0,0,0.2)] hover:shadow-[6px_6px_0px_0px_rgba(0,0,0,0.2)] hover:-translate-y-0.5 transition-all min-w-[160px] h-12 text-sm font-bold uppercase tracking-wider"
        >
          TIẾP TỤC ĐẾN CHI TIẾT
          <ArrowRight className="ml-2 h-4 w-4" />
        </Button>
      </div>
    </div>
  );
};

export default StepBasicInfo;

import { useState, useEffect, lazy, Suspense, useRef } from "react";
import {
  ArrowLeft,
  ArrowRight,
  ImageIcon,
  Info,
  MapPin,
  Phone,
} from "lucide-react";
import usePlaceStore from "@/stores/placeStore";
import {
  Button,
  Input,
  Label,
  Card,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui";
import { Textarea } from "@/components/ui/textarea";
import ImageUploader from "./ImageUploader";
import PriceRangeSlider from "./PriceRangeSlider";
import TagSelector from "./TagSelector";
import OpeningHoursEditor from "./OpeningHoursEditor";
import { useToast } from "@/hooks/use-toast";

// Lazy load MapPicker (heavy component with maplibre-gl)
const MapPicker = lazy(() => import("./MapPicker"));

const MapSkeleton = () => (
  <div className="w-full h-[500px] rounded-lg bg-slate-100 animate-pulse flex items-center justify-center">
    <MapPin className="h-12 w-12 text-slate-300" />
  </div>
);

/**
 * STEP 2: DETAILS
 * Chi tiết: Mô tả, hình ảnh, vị trí, liên hệ
 */

const StepDetails = () => {
  const { toast } = useToast();
  const { wizardData, updateWizardData, nextStep, prevStep, loading } =
    usePlaceStore();

  const [errors, setErrors] = useState({});
  const lastLookupRef = useRef({ lat: null, lng: null });

  const validate = () => {
    const newErrors = {};

    if (!wizardData.latitude || !wizardData.longitude) {
      newErrors.location = "Vui lòng chọn vị trí trên bản đồ";
    }

    if (!wizardData.description?.trim()) {
      newErrors.description = "Vui lòng nhập mô tả chi tiết";
    }

    // Validate phone format (optional)
    if (
      wizardData.phone &&
      !/^[0-9]{10,11}$/.test(wizardData.phone.replace(/\s/g, ""))
    ) {
      newErrors.phone = "Số điện thoại không hợp lệ (10-11 chữ số)";
    }

    // Validate email format (optional)
    if (
      wizardData.email &&
      !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(wizardData.email)
    ) {
      newErrors.email = "Email không hợp lệ";
    }

    // Validate website URL (optional)
    if (wizardData.website && !/^https?:\/\/.+/.test(wizardData.website)) {
      newErrors.website =
        "URL website không hợp lệ (cần bắt đầu với http:// hoặc https://)";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  // Auto-lookup location when map marker changes
  useEffect(() => {
    const lat = wizardData.latitude;
    const lng = wizardData.longitude;

    if (!lat || !lng) return;

    // Check if this is the same location as last lookup
    if (
      lastLookupRef.current.lat === lat &&
      lastLookupRef.current.lng === lng
    ) {
      return;
    }

    const timer = setTimeout(async () => {
      const { lookupLocation } = usePlaceStore.getState();
      const district = await lookupLocation(lat, lng);

      if (district) {
        // Update ref to prevent duplicate lookups
        lastLookupRef.current = { lat, lng };

        toast({
          title: "Đã xác định khu vực",
          description: `Vị trí thuộc ${district.name}, TP. Cần Thơ`,
          variant: "success",
          className: "bg-green-50 border-green-200 text-green-800",
        });
      }
    }, 500); // Debounce 500ms

    return () => clearTimeout(timer);
  }, [wizardData.latitude, wizardData.longitude]);

  const handleNext = () => {
    if (validate()) {
      nextStep();
    } else {
      toast({
        variant: "destructive",
        title: "Lỗi",
        description: "Vui lòng kiểm tra lại thông tin",
      });
    }
  };

  const handleBack = () => {
    prevStep();
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-500">
      <Tabs defaultValue="description" className="w-full">
        <TabsList className="grid w-full grid-cols-4 bg-white border border-black p-0 rounded-none h-auto">
          <TabsTrigger
            value="description"
            className="rounded-none border-r border-black font-mono uppercase text-xs py-3 data-[state=active]:bg-black data-[state=active]:text-white data-[state=active]:shadow-none transition-all"
          >
            <Info className="w-3 h-3 mr-2" /> MÔ TẢ & TAGS
          </TabsTrigger>
          <TabsTrigger
            value="images"
            className="rounded-none border-r border-black font-mono uppercase text-xs py-3 data-[state=active]:bg-black data-[state=active]:text-white data-[state=active]:shadow-none transition-all"
          >
            <ImageIcon className="w-3 h-3 mr-2" /> HÌNH ẢNH
          </TabsTrigger>
          <TabsTrigger
            value="location"
            className="rounded-none border-r border-black font-mono uppercase text-xs py-3 data-[state=active]:bg-black data-[state=active]:text-white data-[state=active]:shadow-none transition-all"
          >
            <MapPin className="w-3 h-3 mr-2" /> VỊ TRÍ
          </TabsTrigger>
          <TabsTrigger
            value="contact"
            className="rounded-none font-mono uppercase text-xs py-3 data-[state=active]:bg-black data-[state=active]:text-white data-[state=active]:shadow-none transition-all"
          >
            <Phone className="w-3 h-3 mr-2" /> LIÊN HỆ
          </TabsTrigger>
        </TabsList>

        {/* Tab 1: Description */}
        <TabsContent value="description" className="space-y-6 mt-6">
          <Card className="p-8 border border-black shadow-hard bg-white rounded-none">
            <div className="space-y-8">
              <div>
                <Label
                  htmlFor="description"
                  className="text-xs font-bold uppercase tracking-wider mb-2 block"
                >
                  MÔ TẢ CHI TIẾT <span className="text-red-500">*</span>
                </Label>
                <div className="bg-gray-50 border border-black p-4 mb-4">
                  <p className="text-[10px] font-mono text-gray-500 uppercase leading-relaxed mb-4">
                    * GIỚI THIỆU VỀ KHÔNG GIAN, PHONG CÁCH, VÀ NHỮNG ĐIỂM ĐẶC
                    BIỆT CỦA ĐỊA ĐIỂM. INFORMATION SHOULD BE DETAILED TO IMPROVE
                    SEO AND USER EXPERIENCE.
                  </p>
                  <Textarea
                    id="description"
                    placeholder="TYPE YOUR DESCRIPTION HERE..."
                    rows={8}
                    value={wizardData.description}
                    onChange={(e) =>
                      updateWizardData({ description: e.target.value })
                    }
                    className={`bg-white rounded-none border-black focus-visible:ring-0 font-mono text-sm resize-none ${errors.description ? "border-red-500" : ""}`}
                  />
                </div>
                {errors.description && (
                  <div className="flex items-center gap-2 mt-2 text-red-500 text-xs font-mono uppercase">
                    <Info className="h-3 w-3" /> {errors.description}
                  </div>
                )}
              </div>

              <div className="border-t border-black border-dashed"></div>

              {/* Price Range */}
              <PriceRangeSlider
                priceRange={wizardData.priceRange}
                priceFrom={wizardData.priceFrom}
                priceTo={wizardData.priceTo}
                onChange={(data) => updateWizardData(data)}
              />

              <div className="border-t border-black border-dashed"></div>

              {/* Tags */}
              <TagSelector
                selectedTags={wizardData.tagIds || []} // Assuming tagIds is the field
                onChange={(tags) => updateWizardData({ tagIds: tags })}
              />

              <div className="border-t border-black border-dashed"></div>

              {/* Opening Hours */}
              <OpeningHoursEditor
                value={wizardData.openingHours || []}
                onChange={(hours) => updateWizardData({ openingHours: hours })}
              />
            </div>
          </Card>
        </TabsContent>

        {/* Tab 2: Images */}
        <TabsContent value="images" className="mt-6">
          <Card className="p-6 border-slate-200 shadow-sm bg-slate-50/30">
            <div className="mb-4">
              <h3 className="text-base font-semibold text-slate-800">
                Hình ảnh địa điểm
              </h3>
              <p className="text-sm text-slate-500">
                Đăng tải hình ảnh đẹp nhất để thu hút khách hàng. Ảnh bìa sẽ
                được hiển thị đầu tiên.
              </p>
            </div>
            <ImageUploader
              images={wizardData.images || []}
              onChange={(images) => updateWizardData({ images })}
            />
          </Card>
        </TabsContent>

        {/* Tab 3: Location */}
        <TabsContent value="location" className="mt-6">
          <div className="space-y-2">
            <div className="flex justify-between items-end mb-2">
              <div>
                <h3 className="text-base font-semibold text-slate-800">
                  Ghim vị trí trên bản đồ
                </h3>
                <p className="text-sm text-slate-500">
                  Kéo marker đến vị trí chính xác của địa điểm
                </p>
              </div>
              {errors.location && (
                <span className="text-sm font-medium text-red-500 bg-red-50 px-3 py-1 rounded-full border border-red-200">
                  {errors.location}
                </span>
              )}
            </div>
            <Suspense fallback={<MapSkeleton />}>
              <MapPicker
                latitude={wizardData.latitude}
                longitude={wizardData.longitude}
                onChange={(lat, lng) =>
                  updateWizardData({ latitude: lat, longitude: lng })
                }
                error={errors.location}
              />
            </Suspense>
          </div>
        </TabsContent>

        {/* Tab 4: Contact Info */}
        <TabsContent value="contact" className="space-y-4 mt-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Card className="p-5 border-slate-200 bg-white">
              <h4 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <Phone className="h-4 w-4 text-primary" /> Thông tin chính
              </h4>
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="phone">Số điện thoại</Label>
                  <Input
                    id="phone"
                    type="tel"
                    placeholder="0909 123 456"
                    value={wizardData.phone}
                    onChange={(e) =>
                      updateWizardData({ phone: e.target.value })
                    }
                    className={errors.phone && "border-red-500"}
                  />
                  {errors.phone && (
                    <p className="text-xs text-red-500">{errors.phone}</p>
                  )}
                </div>
                <div className="space-y-2">
                  <Label htmlFor="email">Email</Label>
                  <Input
                    id="email"
                    type="email"
                    placeholder="contact@example.com"
                    value={wizardData.email}
                    onChange={(e) =>
                      updateWizardData({ email: e.target.value })
                    }
                    className={errors.email && "border-red-500"}
                  />
                  {errors.email && (
                    <p className="text-xs text-red-500">{errors.email}</p>
                  )}
                </div>
              </div>
            </Card>

            <Card className="p-5 border-slate-200 bg-white">
              <h4 className="font-semibold text-slate-800 mb-4 flex items-center gap-2">
                <MapPin className="h-4 w-4 text-blue-500" /> Mạng xã hội & Web
              </h4>
              <div className="space-y-4">
                <div className="space-y-2">
                  <Label htmlFor="website">Website</Label>
                  <Input
                    id="website"
                    type="url"
                    placeholder="https://example.com"
                    value={wizardData.website}
                    onChange={(e) =>
                      updateWizardData({ website: e.target.value })
                    }
                    className={errors.website && "border-red-500"}
                  />
                  {errors.website && (
                    <p className="text-xs text-red-500">{errors.website}</p>
                  )}
                </div>
                <div className="space-y-2">
                  <Label htmlFor="facebook">Facebook</Label>
                  <Input
                    id="facebook"
                    placeholder="https://facebook.com/yourpage"
                    value={wizardData.facebook}
                    onChange={(e) =>
                      updateWizardData({ facebook: e.target.value })
                    }
                  />
                </div>
              </div>
            </Card>
          </div>
        </TabsContent>
      </Tabs>

      {/* Actions */}
      <div className="flex justify-between pt-6 border-t border-dashed">
        <Button
          variant="outline"
          onClick={handleBack}
          disabled={loading}
          size="lg"
          className="border-slate-300 hover:bg-slate-50 text-slate-600"
        >
          <ArrowLeft className="mr-2 h-4 w-4" />
          Quay lại
        </Button>
        <Button
          onClick={handleNext}
          disabled={loading}
          size="lg"
          className="bg-primary hover:bg-primary/90 min-w-[140px]"
        >
          Tiếp theo
          <ArrowRight className="ml-2 h-4 w-4" />
        </Button>
      </div>
    </div>
  );
};

export default StepDetails;

import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import {
  ArrowLeft,
  Check,
  MapPin,
  Phone,
  Mail,
  Globe,
  Facebook,
  Tag,
  Loader2,
  Calendar,
  Clock,
  Info,
  DollarSign,
  ImageIcon,
} from "lucide-react";
import usePlaceStore from "@/stores/placeStore";
import useCategoryStore from "@/stores/categoryStore";
import useTagStore from "@/stores/tagStore";
import * as districtService from "@/apis/districtService";
import * as wardService from "@/apis/wardService";
import { Button, Card, Badge, Separator } from "@/components/ui";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";

/**
 * STEP 3: PREVIEW & SUBMIT
 * Xem trước thông tin và gửi
 * T.I.M Style Redesign
 */

const StepPreview = ({ isEditMode }) => {
  const navigate = useNavigate();
  const { toast } = useToast();

  const { wizardData, prevStep, loading, createPlace, updatePlace } =
    usePlaceStore();

  const { categories } = useCategoryStore();
  const { tags, fetchTags } = useTagStore();

  const [district, setDistrict] = useState(null);
  const [ward, setWard] = useState(null);
  const [submitting, setSubmitting] = useState(false);

  // Load district and ward info
  useEffect(() => {
    if (wizardData.districtId) {
      districtService
        .getDistrictById(wizardData.districtId)
        .then((res) => setDistrict(res.data))
        .catch(() => {});
    }

    if (wizardData.wardId) {
      wardService
        .getWardById(wizardData.wardId)
        .then((res) => setWard(res.data))
        .catch(() => {});
    }
  }, [wizardData.districtId, wizardData.wardId]);

  // Load tags if not loaded
  useEffect(() => {
    if (tags.length === 0) {
      fetchTags();
    }
     
  }, []);

  const category = categories.find((cat) => cat.id === wizardData.categoryId);

  const handleSubmit = async () => {
    setSubmitting(true);
    try {
      const placeData = {
        ...wizardData,
        // Ensure arrays are properly formatted
        images: wizardData.images || [],
        tagIds: wizardData.tagIds || [],
        openingHours: wizardData.openingHours || [],
        amenities: wizardData.amenities || [],
      };

      if (isEditMode) {
        // Update existing place
        const updateId = wizardData.id;

        if (!updateId) {
          console.error("Missing ID in wizardData", wizardData);
          toast({
            variant: "destructive",
            title: "Lỗi",
            description: "Không xác định được ID địa điểm",
          });
          return;
        }

        await updatePlace(updateId, placeData);
        toast({
          title: "Thành công",
          description: "Cập nhật địa điểm thành công",
        });
      } else {
        // Create new place
        await createPlace(placeData);
        toast({
          title: "Thành công",
          description: "Tạo địa điểm mới thành công",
        });
      }

      // Navigate back to list
      navigate("/admin/places");
    } catch (error) {
      console.error(error);
      toast({
        variant: "destructive",
        title: "Lỗi",
        description: error.message || "Có lỗi xảy ra khi lưu địa điểm",
      });
    } finally {
      setSubmitting(false);
    }
  };

  const handleBack = () => {
    prevStep();
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-6 duration-500 pb-20">
      {/* Summary Header */}
      <div className="bg-white border-2 border-black p-6 shadow-[4px_4px_0px_0px_rgba(0,0,0,1)]">
        <div className="flex justify-between items-start">
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <Badge className="bg-black text-white hover:bg-black rounded-none font-mono text-xs uppercase px-2 py-1">
                {category?.name || "CHƯA PHÂN LOẠI"}
              </Badge>
            </div>
            <h2 className="text-3xl font-black uppercase tracking-tight">
              {wizardData.name || "UNTITLED_PLACE"}
            </h2>
            <div className="flex items-center gap-2 text-sm font-mono text-gray-600">
              <MapPin className="w-4 h-4" />
              <span>
                {wizardData.address}
                {district && `, ${district.name}`}
                {ward && `, ${ward.name}`}
              </span>
            </div>
          </div>

          {/* Thumbnail Preview Removed - Moved to Gallery */}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {/* Main Content Review */}
        <div className="md:col-span-2 space-y-6">
          {/* Images Gallery */}
          <Card className="border-2 border-gray-200 rounded-sm p-4 bg-white">
            <div className="flex items-center gap-2 mb-3 border-b border-gray-100 pb-2">
              <ImageIcon className="w-4 h-4 text-gray-400" />
              <span className="font-mono font-bold uppercase text-xs text-gray-500">
                THƯ VIỆN ẢNH ({wizardData.images?.length || 0})
              </span>
            </div>
            {wizardData.images && wizardData.images.length > 0 ? (
              <div className="grid grid-cols-4 gap-2">
                {wizardData.images.map((img, idx) => (
                  <div
                    key={idx}
                    className="aspect-square border border-gray-200 bg-gray-50 relative group"
                  >
                    <img
                      src={img.imageData}
                      alt={`Preview ${idx}`}
                      className="w-full h-full object-cover transition-all"
                    />
                    {img.isCover && (
                      <div className="absolute top-1 left-1 bg-emerald-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-[1px] font-mono">
                        COVER
                      </div>
                    )}
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-xs text-gray-400 italic font-mono text-center py-4">
                -- CHƯA CÓ HÌNH ẢNH --
              </p>
            )}
          </Card>

          {/* Description */}
          <Card className="border-2 border-gray-200 rounded-sm p-4 bg-white">
            <div className="flex items-center gap-2 mb-3 border-b border-gray-100 pb-2">
              <Info className="w-4 h-4 text-gray-400" />
              <span className="font-mono font-bold uppercase text-xs text-gray-500">
                MÔ TẢ
              </span>
            </div>
            <p className="text-sm leading-relaxed text-gray-700 whitespace-pre-line font-mono">
              {wizardData.description || "[CHƯA CÓ DỮ LIỆU]"}
            </p>
          </Card>

          {/* Tags & Price Summary */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <Card className="border-2 border-gray-200 rounded-sm p-4 bg-white h-auto">
              <div className="flex items-center gap-2 mb-3 border-b border-gray-100 pb-2">
                <Tag className="w-4 h-4 text-gray-400" />
                <span className="font-mono font-bold uppercase text-xs text-gray-500">
                  TAGS & THUỘC TÍNH
                </span>
              </div>
              <div className="flex flex-wrap gap-2">
                {wizardData.tagIds && wizardData.tagIds.length > 0 ? (
                  wizardData.tagIds.map((tagId) => {
                    const tag = tags.find((t) => t.id === tagId);
                    return tag ? (
                      <span
                        key={tagId}
                        className="px-2 py-1 bg-gray-100 text-gray-600 font-mono text-[10px] uppercase border border-gray-200"
                      >
                        #{tag.name}
                      </span>
                    ) : null;
                  })
                ) : (
                  <span className="text-xs text-gray-400 italic font-mono">
                    -- KHÔNG --
                  </span>
                )}
              </div>
            </Card>

            <Card className="border-2 border-gray-200 rounded-sm p-4 bg-white h-auto">
              <div className="flex items-center gap-2 mb-3 border-b border-gray-100 pb-2">
                <DollarSign className="w-4 h-4 text-gray-400" />
                <span className="font-mono font-bold uppercase text-xs text-gray-500">
                  GIÁ CẢ
                </span>
              </div>
              <div className="space-y-1">
                {wizardData.priceRange ? (
                  <div className="flex items-center justify-between">
                    <span className="text-xs font-mono text-gray-500">
                      PHÂN KHÚC:
                    </span>
                    <span className="text-sm font-bold">
                      {wizardData.priceRange}
                    </span>
                  </div>
                ) : null}
                <div className="flex items-center justify-between pt-2">
                  <span className="text-xs font-mono text-gray-500">
                    KHOẢNG:
                  </span>
                  <span className="text-sm font-mono">
                    {wizardData.priceFrom
                      ? Number(wizardData.priceFrom).toLocaleString("vi-VN")
                      : "0"}
                    {" - "}
                    {wizardData.priceTo
                      ? Number(wizardData.priceTo).toLocaleString("vi-VN")
                      : "0"}
                  </span>
                </div>
              </div>
            </Card>
          </div>
        </div>

        {/* Sidebar Info */}
        <div className="space-y-6">
          <Card className="border-2 border-gray-200 rounded-sm p-4 bg-gray-50">
            <div className="flex items-center gap-2 mb-3 border-b border-gray-200 pb-2">
              <Clock className="w-4 h-4 text-gray-400" />
              <span className="font-mono font-bold uppercase text-xs text-gray-500">
                LỊCH TRÌNH
              </span>
            </div>
            <div className="space-y-2">
              {wizardData.openingHours && wizardData.openingHours.length > 0 ? (
                wizardData.openingHours.map((slot, idx) => (
                  <div
                    key={idx}
                    className="flex justify-between items-center text-xs font-mono"
                  >
                    <span className="font-bold w-6">
                      {slot.dayOfWeek === 8 ? "CN" : `T${slot.dayOfWeek}`}
                    </span>
                    <span
                      className={cn(
                        slot.isClosed ? "text-red-500" : "text-emerald-600",
                        "flex-1 text-right",
                      )}
                    >
                      {slot.isClosed
                        ? "ĐÓNG"
                        : `${slot.openTime} - ${slot.closeTime}`}
                    </span>
                  </div>
                ))
              ) : (
                <span className="text-xs text-gray-400 italic font-mono block text-center py-4">
                  -- CHƯA CÓ LỊCH --
                </span>
              )}
            </div>
          </Card>

          <Card className="border-2 border-gray-200 rounded-sm p-4 bg-white">
            <div className="flex items-center gap-2 mb-3 border-b border-gray-100 pb-2">
              <Phone className="w-4 h-4 text-gray-400" />
              <span className="font-mono font-bold uppercase text-xs text-gray-500">
                LIÊN HỆ
              </span>
            </div>
            <div className="space-y-3 font-mono text-xs">
              <div className="flex gap-2 items-center">
                <Phone className="w-3 h-3 text-gray-400" />
                <span>{wizardData.phone || "--"}</span>
              </div>
              <div className="flex gap-2 items-center">
                <Mail className="w-3 h-3 text-gray-400" />
                <span className="break-all">{wizardData.email || "--"}</span>
              </div>
              <div className="flex gap-2 items-center">
                <Globe className="w-3 h-3 text-gray-400" />
                <span className="truncate max-w-[150px]">
                  {wizardData.website || "--"}
                </span>
              </div>
            </div>
          </Card>
        </div>
      </div>

      {/* Actions */}
      <div className="flex justify-between pt-6 border-t-2 border-black border-dashed mt-8">
        <Button
          variant="outline"
          onClick={handleBack}
          disabled={submitting}
          size="lg"
          className="rounded-none border-2 border-black hover:bg-gray-100 font-mono font-bold uppercase"
        >
          <ArrowLeft className="mr-2 h-4 w-4" />
          QUAY LẠI
        </Button>
        <Button
          onClick={handleSubmit}
          disabled={submitting || loading}
          size="lg"
          className="rounded-none bg-black text-white hover:bg-gray-900 min-w-[200px] font-mono font-bold uppercase shadow-[4px_4px_0px_0px_rgba(200,200,200,1)] hover:shadow-none hover:translate-x-[2px] hover:translate-y-[2px] transition-all"
        >
          {submitting ? (
            <>
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
              ĐANG XỬ LÝ...
            </>
          ) : (
            <>
              <Check className="mr-2 h-4 w-4" />
              {isEditMode ? "CẬP NHẬT NGAY" : "TẠO ĐỊA ĐIỂM"}
            </>
          )}
        </Button>
      </div>
    </div>
  );
};

export default StepPreview;

