          <DialogTitle className="text-xl flex items-center gap-3 font-bold uppercase tracking-wider">
            <div className="h-8 w-8 bg-black text-white flex items-center justify-center">
              <Settings className="h-5 w-5" />
            </div>
            QUẢN LÝ - {role.displayName}
          </DialogTitle>
          <DialogDescription className="text-gray-500 font-mono text-xs">
            {role.description || "Cấu hình quyền hạn và quản lý users"}
          </DialogDescription>
        </DialogHeader>

        <Tabs
          value={activeTab}
          onValueChange={setActiveTab}
          className="flex-1 flex flex-col px-6 py-4 overflow-hidden"
        >
          <TabsList className="grid w-full grid-cols-2 mb-4 bg-gray-100 border border-black rounded-none p-1 gap-1">
            <TabsTrigger
              value="permissions"
              className="flex items-center gap-2 rounded-none data-[state=active]:bg-black data-[state=active]:text-white transition-all font-bold uppercase tracking-wider data-[state=active]:shadow-none"
            >
              <Shield className="h-4 w-4" />
              Quyền hạn
            </TabsTrigger>
            <TabsTrigger
              value="users"
              className="flex items-center gap-2 rounded-none data-[state=active]:bg-black data-[state=active]:text-white transition-all font-bold uppercase tracking-wider data-[state=active]:shadow-none"
            >
              <Users className="h-4 w-4" />
              Users ({role.userCount || 0})
            </TabsTrigger>
          </TabsList>

          <div className="flex-1 overflow-hidden">
            <TabsContent value="permissions" className="h-full mt-0">
              <ScrollArea className="h-full pr-4">
                <RolePermissionTab
                  role={role}
                  onUpdated={onUpdated}
                  onClose={() => onOpenChange(false)}
                />
              </ScrollArea>
            </TabsContent>

            <TabsContent value="users" className="h-full mt-0">
              <ScrollArea className="h-full pr-4">
                <RoleUsersTab role={role} onUpdated={onUpdated} />
              </ScrollArea>
            </TabsContent>
          </div>
        </Tabs>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect, useMemo } from "react";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/Label";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { PermissionCheckbox } from "./permission-checkbox";
import { roleService } from "@/apis/roleService";
import { permissionService } from "@/apis/permissionService";
import { MODULE_DISPLAY_NAMES } from "@/constants/permissions";
import Search from "lucide-react/dist/esm/icons/search";
import CheckCircle2 from "lucide-react/dist/esm/icons/check-circle-2";
import XCircle from "lucide-react/dist/esm/icons/x-circle";
import Save from "lucide-react/dist/esm/icons/save";
import Lightbulb from "lucide-react/dist/esm/icons/lightbulb";
import ChevronDown from "lucide-react/dist/esm/icons/chevron-down";
import ChevronUp from "lucide-react/dist/esm/icons/chevron-up";
import { toast } from "sonner";

export function RolePermissionModal({
  open,
  onOpenChange,
  role,
  onPermissionsUpdated,
}) {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [allPermissions, setAllPermissions] = useState({});
  const [selectedPermissions, setSelectedPermissions] = useState(new Set());
  const [initialPermissions, setInitialPermissions] = useState(new Set());
  const [search, setSearch] = useState("");
  const [moduleFilter, setModuleFilter] = useState("all");
  const [expandedModules, setExpandedModules] = useState(new Set());

  useEffect(() => {
    if (open && role) {
      fetchData();
    }
  }, [open, role]);

  const fetchData = async () => {
    try {
      setLoading(true);

      const [permissionsResponse, rolePermissionsResponse] = await Promise.all([
        permissionService.getPermissionsByModule(false),
        roleService.getRolePermissions(role.id),
      ]);

      console.warn("Permissions response:", permissionsResponse);
      console.warn("Role permissions response:", rolePermissionsResponse);

      if (permissionsResponse && permissionsResponse.permissions) {
        setAllPermissions(permissionsResponse.permissions);

        const currentPermissionIds = new Set();
        if (rolePermissionsResponse && rolePermissionsResponse.permissions) {
          Object.values(rolePermissionsResponse.permissions).forEach(
            (perms) => {
              perms.forEach((p) => currentPermissionIds.add(p.id));
            },
          );
        }

        setSelectedPermissions(currentPermissionIds);
        setInitialPermissions(currentPermissionIds);

        const modules = Object.keys(permissionsResponse.permissions);
        setExpandedModules(new Set(modules.slice(0, 3)));
      }
    } catch (error) {
      console.error("Lỗi khi tải dữ liệu:", error);
      toast.error("Không thể tải danh sách quyền");
    } finally {
      setLoading(false);
    }
  };

  const handleTogglePermission = (permissionId) => {
    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(permissionId)) {
        newSet.delete(permissionId);
      } else {
        newSet.add(permissionId);
      }
      return newSet;
    });
  };

  const handleSelectAll = () => {
    const allIds = new Set();
    Object.values(filteredPermissions).forEach((perms) => {
      perms.forEach((p) => allIds.add(p.id));
    });
    setSelectedPermissions(allIds);
  };

  const handleDeselectAll = () => {
    setSelectedPermissions(new Set());
  };

  const handleToggleModule = (module) => {
    const modulePermissions = filteredPermissions[module] || [];
    const moduleIds = modulePermissions.map((p) => p.id);
    const allSelected = moduleIds.every((id) => selectedPermissions.has(id));

    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (allSelected) {
        moduleIds.forEach((id) => newSet.delete(id));
      } else {
        moduleIds.forEach((id) => newSet.add(id));
      }
      return newSet;
    });
  };

  const handleSave = async () => {
    try {
      setSaving(true);
      const permissionIds = Array.from(selectedPermissions);

      await roleService.updateRolePermissions(role.id, permissionIds);

      toast.success("Cập nhật quyền thành công");
      setInitialPermissions(new Set(selectedPermissions));

      if (onPermissionsUpdated) {
        onPermissionsUpdated();
      }

      onOpenChange(false);
    } catch (error) {
      console.error("Lỗi khi cập nhật quyền:", error);
      toast.error(error.response?.data?.message || "Không thể cập nhật quyền");
    } finally {
      setSaving(false);
    }
  };

  const filteredPermissions = useMemo(() => {
    let result = { ...allPermissions };

    if (moduleFilter !== "all") {
      result = { [moduleFilter]: allPermissions[moduleFilter] || [] };
    }

    if (search.trim()) {
      const lowerSearch = search.toLowerCase();
      const filtered = {};

      Object.entries(result).forEach(([module, perms]) => {
        const matched = perms.filter(
          (p) =>
            p.name.toLowerCase().includes(lowerSearch) ||
            p.displayName.toLowerCase().includes(lowerSearch),
        );
        if (matched.length > 0) {
          filtered[module] = matched;
        }
      });

      result = filtered;
    }

    return result;
  }, [allPermissions, moduleFilter, search]);

  const stats = useMemo(() => {
    let totalFiltered = 0;
    let selectedFiltered = 0;

    Object.values(filteredPermissions).forEach((perms) => {
      totalFiltered += perms.length;
      selectedFiltered += perms.filter((p) =>
        selectedPermissions.has(p.id),
      ).length;
    });

    return {
      total: totalFiltered,
      selected: selectedFiltered,
      percentage:
        totalFiltered > 0 ? (selectedFiltered / totalFiltered) * 100 : 0,
    };
  }, [filteredPermissions, selectedPermissions]);

  const hasChanges = useMemo(() => {
    if (selectedPermissions.size !== initialPermissions.size) return true;
    for (const id of selectedPermissions) {
      if (!initialPermissions.has(id)) return true;
    }
    return false;
  }, [selectedPermissions, initialPermissions]);

  const getSuggestionForRole = () => {
    const suggestions = {
      admin:
        "Vai trò Admin nên có quyền quản lý người dùng và duyệt nội dung, nhưng không nên thay đổi vai trò hoặc cấu hình hệ thống.",
      business:
        "Chủ doanh nghiệp chỉ nên quản lý địa điểm, dịch vụ và booking của chính mình.",
      staff:
        "Nhân viên hỗ trợ nên có quyền xem và xử lý báo cáo, ẩn đánh giá vi phạm.",
      guest: "Khách không có quyền truy cập vào trang quản trị.",
    };
    return suggestions[role?.name] || null;
  };

  const toggleModuleExpand = (module) => {
    setExpandedModules((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(module)) {
        newSet.delete(module);
      } else {
        newSet.add(module);
      }
      return newSet;
    });
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl h-[90vh] flex flex-col">
        <DialogHeader>
          <DialogTitle className="text-xl">
            Quản lý quyền hạn - {role?.displayName}
          </DialogTitle>
          <DialogDescription>
            {role?.description || "Cấu hình quyền hạn cho vai trò này"}
          </DialogDescription>
        </DialogHeader>

        {loading ? (
          <div className="space-y-4 py-4">
            <Skeleton className="h-10 w-full" />
            <Skeleton className="h-10 w-full" />
            <Skeleton className="h-40 w-full" />
            <Skeleton className="h-40 w-full" />
          </div>
        ) : (
          <>
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                <div className="relative flex-1">
                  <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                  <Input
                    placeholder="Tìm quyền..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="pl-9"
                  />
                </div>
                <Select value={moduleFilter} onValueChange={setModuleFilter}>
                  <SelectTrigger className="w-[200px]">
                    <SelectValue placeholder="Lọc theo module" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="all">Tất cả modules</SelectItem>
                    {Object.keys(allPermissions).map((module) => (
                      <SelectItem key={module} value={module}>
                        {MODULE_DISPLAY_NAMES[module] || module}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="flex items-center justify-between">
                <div className="space-y-1">
                  <p className="text-sm font-medium">
                    Đã chọn: {stats.selected} / {stats.total} quyền
                  </p>
                  <Progress
                    value={stats.percentage}
                    className="h-2 w-[200px]"
                  />
                </div>
                <div className="flex gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleSelectAll}
                    disabled={stats.selected === stats.total}
                  >
                    <CheckCircle2 className="h-4 w-4 mr-2" />
                    Chọn tất cả
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleDeselectAll}
                    disabled={stats.selected === 0}
                  >
                    <XCircle className="h-4 w-4 mr-2" />
                    Bỏ chọn
                  </Button>
                </div>
              </div>

              {getSuggestionForRole() && (
                <Alert>
                  <Lightbulb className="h-4 w-4" />
                  <AlertDescription>{getSuggestionForRole()}</AlertDescription>
                </Alert>
              )}
            </div>

            <ScrollArea className="flex-1 pr-4 h-[calc(90vh-380px)]">
              <div className="space-y-3 pb-4">
                {Object.keys(filteredPermissions).length === 0 ? (
                  <div className="text-center py-8 text-muted-foreground">
                    Không tìm thấy quyền nào
                  </div>
                ) : (
                  Object.entries(filteredPermissions).map(
                    ([module, permissions]) => {
                      const moduleSelected = permissions.filter((p) =>
                        selectedPermissions.has(p.id),
                      ).length;
                      const moduleTotal = permissions.length;
                      const isExpanded = expandedModules.has(module);

                      return (
                        <div
                          key={module}
                          className="border rounded-lg overflow-hidden"
                        >
                          <div
                            className="flex items-center justify-between p-4 bg-muted/50 cursor-pointer hover:bg-muted"
                            onClick={() => toggleModuleExpand(module)}
                          >
                            <div className="flex items-center gap-3">
                              <Checkbox
                                checked={moduleSelected === moduleTotal}
                                onCheckedChange={() =>
                                  handleToggleModule(module)
                                }
                                onClick={(e) => e.stopPropagation()}
                              />
                              <div>
                                <Label className="font-semibold cursor-pointer">
                                  {MODULE_DISPLAY_NAMES[module] || module}
                                </Label>
                                <p className="text-xs text-muted-foreground">
                                  {moduleSelected}/{moduleTotal} quyền
                                </p>
                              </div>
                            </div>
                            <div className="flex items-center gap-2">
                              <Badge variant="secondary">{module}</Badge>
                              {isExpanded ? (
                                <ChevronUp className="h-4 w-4" />
                              ) : (
                                <ChevronDown className="h-4 w-4" />
                              )}
                            </div>
                          </div>

                          {isExpanded && (
                            <div className="p-4 space-y-2 bg-background">
                              {permissions.map((permission) => (
                                <PermissionCheckbox
                                  key={permission.id}
                                  permission={permission}
                                  checked={selectedPermissions.has(
                                    permission.id,
                                  )}
                                  onCheckedChange={() =>
                                    handleTogglePermission(permission.id)
                                  }
                                />
                              ))}
                            </div>
                          )}
                        </div>
                      );
                    },
                  )
                )}
              </div>
            </ScrollArea>

            <DialogFooter>
              <Button variant="outline" onClick={() => onOpenChange(false)}>
                Hủy
              </Button>
              <Button onClick={handleSave} disabled={!hasChanges || saving}>
                {saving ? (
                  <>Đang lưu...</>
                ) : (
                  <>
                    <Save className="h-4 w-4 mr-2" />
                    Lưu thay đổi
                  </>
                )}
              </Button>
            </DialogFooter>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect, useMemo } from "react";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/Label";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { PermissionCheckbox } from "./permission-checkbox";
import { roleService } from "@/apis/roleService";
import { permissionService } from "@/apis/permissionService";
import { MODULE_DISPLAY_NAMES } from "@/constants/permissions";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import {
  Search,
  CheckCircle,
  XCircle,
  ChevronDown,
  Save,
  RefreshCw,
  SearchX,
} from "lucide-react";

export function RolePermissionTab({ role, onUpdated, onClose }) {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [allPermissions, setAllPermissions] = useState({});
  const [selectedPermissions, setSelectedPermissions] = useState(new Set());
  const [initialPermissions, setInitialPermissions] = useState(new Set());
  const [search, setSearch] = useState("");
  const [moduleFilter, setModuleFilter] = useState("all");
  const [expandedModules, setExpandedModules] = useState(new Set());

  useEffect(() => {
    fetchData();
  }, [role]);

  const fetchData = async () => {
    try {
      setLoading(true);

      const [permissionsResponse, rolePermissionsResponse] = await Promise.all([
        permissionService.getPermissionsByModule(false),
        roleService.getRolePermissions(role.id),
      ]);

      if (permissionsResponse?.success && permissionsResponse.permissions) {
        setAllPermissions(permissionsResponse.permissions);

        const currentPermissionIds = new Set();
        if (
          rolePermissionsResponse?.success &&
          rolePermissionsResponse.data?.permissions
        ) {
          Object.values(rolePermissionsResponse.data.permissions).forEach(
            (perms) => {
              perms.forEach((p) => currentPermissionIds.add(p.id));
            },
          );
        }

        setSelectedPermissions(currentPermissionIds);
        setInitialPermissions(currentPermissionIds);

        const modules = Object.keys(permissionsResponse.permissions);
        setExpandedModules(new Set(modules.slice(0, 3)));
      }
    } catch (error) {
      const errorMsg =
        error.response?.data?.message ||
        error.message ||
        "Không thể tải danh sách quyền";
      toast.error(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  const handleTogglePermission = (permissionId) => {
    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(permissionId)) {
        newSet.delete(permissionId);
      } else {
        newSet.add(permissionId);
      }
      return newSet;
    });
  };

  const handleSelectAll = () => {
    const allIds = new Set();
    Object.values(filteredPermissions).forEach((perms) => {
      perms.forEach((p) => allIds.add(p.id));
    });
    setSelectedPermissions(allIds);
  };

  const handleDeselectAll = () => {
    setSelectedPermissions(new Set());
  };

  const handleToggleModule = (module) => {
    const modulePermissions = filteredPermissions[module] || [];
    const moduleIds = modulePermissions.map((p) => p.id);
    const allSelected = moduleIds.every((id) => selectedPermissions.has(id));

    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (allSelected) {
        moduleIds.forEach((id) => newSet.delete(id));
      } else {
        moduleIds.forEach((id) => newSet.add(id));
      }
      return newSet;
    });
  };

  const handleSave = async () => {
    try {
      setSaving(true);
      const permissionIds = Array.from(selectedPermissions);

      const response = await roleService.updateRolePermissions(
        role.id,
        permissionIds,
      );

      if (response?.success) {
        toast.success(response.message || "Cập nhật quyền thành công");
        setInitialPermissions(new Set(selectedPermissions));

        if (onUpdated) {
          onUpdated();
        }

        onClose();
      }
    } catch (error) {
      const errorMsg =
        error.response?.data?.message ||
        error.message ||
        "Không thể cập nhật quyền";
      toast.error(errorMsg);
    } finally {
      setSaving(false);
    }
  };

  const filteredPermissions = useMemo(() => {
    let result = { ...allPermissions };

    if (moduleFilter !== "all") {
      result = { [moduleFilter]: allPermissions[moduleFilter] || [] };
    }

    if (search.trim()) {
      const lowerSearch = search.toLowerCase();
      const filtered = {};

      Object.entries(result).forEach(([module, perms]) => {
        const matched = perms.filter(
          (p) =>
            p.name.toLowerCase().includes(lowerSearch) ||
            p.displayName.toLowerCase().includes(lowerSearch),
        );
        if (matched.length > 0) {
          filtered[module] = matched;
        }
      });

      result = filtered;
    }

    return result;
  }, [allPermissions, moduleFilter, search]);

  const stats = useMemo(() => {
    let totalFiltered = 0;
    let selectedFiltered = 0;

    Object.values(filteredPermissions).forEach((perms) => {
      totalFiltered += perms.length;
      selectedFiltered += perms.filter((p) =>
        selectedPermissions.has(p.id),
      ).length;
    });

    return {
      total: totalFiltered,
      selected: selectedFiltered,
      percentage:
        totalFiltered > 0 ? (selectedFiltered / totalFiltered) * 100 : 0,
    };
  }, [filteredPermissions, selectedPermissions]);

  const hasChanges = useMemo(() => {
    if (selectedPermissions.size !== initialPermissions.size) return true;
    for (const id of selectedPermissions) {
      if (!initialPermissions.has(id)) return true;
    }
    return false;
  }, [selectedPermissions, initialPermissions]);

  const toggleModuleExpand = (module) => {
    setExpandedModules((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(module)) {
        newSet.delete(module);
      } else {
        newSet.add(module);
      }
      return newSet;
    });
  };

  if (loading) {
    return (
      <div className="space-y-4 py-4">
        <Skeleton className="h-10 w-full border border-black" />
        <Skeleton className="h-10 w-full border border-black" />
        <Skeleton className="h-40 w-full border border-black" />
        <Skeleton className="h-40 w-full border border-black" />
      </div>
    );
  }

  return (
    <div className="space-y-4 pb-4">
      {/* Search and Filter */}
      <div className="flex flex-col sm:flex-row items-center gap-3">
        <div className="relative flex-1 w-full">
          <div className="absolute left-0 top-0 h-full w-10 bg-black flex items-center justify-center text-white">
            <Search className="h-4 w-4" />
          </div>
          <Input
            placeholder="TÌM KIẾM QUYỀN..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-12 h-10 rounded-none border border-black bg-white focus-visible:ring-0 focus-visible:border-black focus:bg-yellow-50 uppercase text-xs font-mono"
          />
        </div>
        <Select value={moduleFilter} onValueChange={setModuleFilter}>
          <SelectTrigger className="w-full sm:w-[200px] h-10 rounded-none border border-black bg-white uppercase text-xs font-bold">
            <SelectValue placeholder="LỌC MODULE" />
          </SelectTrigger>
          <SelectContent className="rounded-none border-2 border-black bg-white">
            <SelectItem value="all" className="uppercase font-mono text-xs">
              TẤT CẢ MODULES
            </SelectItem>
            {Object.keys(allPermissions).map((module) => (
              <SelectItem
                key={module}
                value={module}
                className="uppercase font-mono text-xs"
              >
                {MODULE_DISPLAY_NAMES[module] || module}
              </SelectItem>
            ))}
          </SelectContent>
        </Select>
      </div>

      {/* Progress and Actions */}
      <div className="bg-white p-4 border border-black flex flex-col sm:flex-row items-center justify-between gap-4">
        <div className="space-y-2 w-full sm:w-auto">
          <div className="flex items-center justify-between sm:justify-start gap-3 text-xs font-bold text-black uppercase tracking-wider">
            <span className="font-mono">
              ĐÃ CHỌN: {stats.selected} / {stats.total}
            </span>
            <span className="bg-[#F3E600] text-black px-2 py-0.5 font-mono">
              {Math.round(stats.percentage)}%
            </span>
          </div>
          <div className="w-full sm:w-[240px] h-1 bg-gray-200 border border-gray-300">
            <div
              className="h-full bg-[#F3E600] transition-all duration-300"
              style={{ width: `${stats.percentage}%` }}
            />
          </div>
        </div>
        <div className="flex gap-2 w-full sm:w-auto">
          <Button
            variant="outline"
            size="sm"
            onClick={handleSelectAll}
            disabled={stats.selected === stats.total}
            className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
          >
            <CheckCircle className="h-3 w-3 mr-2" />
            CHỌN TẤT
          </Button>
          <Button
            variant="outline"
            size="sm"
            onClick={handleDeselectAll}
            disabled={stats.selected === 0}
            className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
          >
            <XCircle className="h-3 w-3 mr-2" />
            BỎ CHỌN
          </Button>
        </div>
      </div>

      {/* Permissions List */}
      <div className="space-y-3">
        {Object.keys(filteredPermissions).length === 0 ? (
          <div className="text-center py-12 text-gray-500 bg-white border border-black border-dashed">
            <SearchX className="h-12 w-12 mx-auto mb-2 opacity-30" />
            <p className="uppercase font-mono text-xs">KHÔNG TÌM THẤY QUYỀN</p>
          </div>
        ) : (
          Object.entries(filteredPermissions).map(([module, permissions]) => {
            const moduleSelected = permissions.filter((p) =>
              selectedPermissions.has(p.id),
            ).length;
            const moduleTotal = permissions.length;
            const isExpanded = expandedModules.has(module);

            return (
              <div
                key={module}
                className="border border-black overflow-hidden transition-all hover:shadow-hard"
              >
                <div
                  className="flex items-center justify-between p-4 bg-white cursor-pointer select-none hover:bg-gray-50 border-l-4 border-l-transparent hover:border-l-[#F3E600] transition-all"
                  onClick={() => toggleModuleExpand(module)}
                >
                  <div className="flex items-center gap-3">
                    <div onClick={(e) => e.stopPropagation()}>
                      <Checkbox
                        checked={
                          moduleSelected === moduleTotal && moduleTotal > 0
                            ? true
                            : moduleSelected > 0
                              ? "indeterminate"
                              : false
                        }
                        onCheckedChange={() => handleToggleModule(module)}
                        className="data-[state=checked]:bg-[#F3E600] data-[state=checked]:border-black data-[state=checked]:text-black rounded-none border-2"
                      />
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="h-8 w-1 bg-black"></div>
                      <div>
                        <Label className="font-bold text-black text-sm cursor-pointer uppercase tracking-tight">
                          {MODULE_DISPLAY_NAMES[module] || module}
                        </Label>
                        <p className="text-xs text-gray-500 font-mono mt-0.5 uppercase">
                          {moduleSelected}/{moduleTotal} QUYỀN
                        </p>
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <Badge
                      variant="secondary"
                      className="bg-black text-white rounded-none px-2.5 py-1 font-mono text-xs uppercase"
                    >
                      {module}
                    </Badge>
                    <ChevronDown
                      className={cn(
                        "h-4 w-4 text-black transition-transform duration-200",
                        isExpanded ? "rotate-180" : "",
                      )}
                    />
                  </div>
                </div>

                {isExpanded && (
                  <div className="p-4 space-y-2 bg-gray-50 border-t-2 border-black">
                    {permissions.map((permission) => (
                      <PermissionCheckbox
                        key={permission.id}
                        permission={permission}
                        checked={selectedPermissions.has(permission.id)}
                        onCheckedChange={() =>
                          handleTogglePermission(permission.id)
                        }
                      />
                    ))}
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>

      {/* Footer Actions */}
      <div className="flex justify-end gap-3 pt-4 mt-6 border-t-2 border-black sticky bottom-0 bg-white p-4 -mx-4 -mb-4 shadow-hard z-10 sm:static sm:bg-transparent sm:p-0 sm:shadow-none">
        <Button
          variant="outline"
          onClick={onClose}
          className="rounded-none border border-black hover:bg-gray-100 uppercase text-xs font-bold"
        >
          HỦY
        </Button>
        <Button
          onClick={handleSave}
          disabled={!hasChanges || saving}
          className="rounded-none bg-black hover:bg-[#F3E600] hover:text-black text-white border border-black shadow-hard uppercase text-xs font-bold"
        >
          {saving ? (
            <span className="flex items-center gap-2">
              <RefreshCw className="h-3 w-3 animate-spin" />
              ĐANG LƯU...
            </span>
          ) : (
            <span className="flex items-center gap-2">
              <Save className="h-3 w-3" />
              LƯU THAY ĐỔI
            </span>
          )}
        </Button>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Skeleton } from "@/components/ui/skeleton";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/Avatar";
import { userPermissionService } from "@/apis/userPermissionService";
import { toast } from "sonner";
import { UserPermissionModal } from "./user-permission-modal";
import { Search, UserCog, Users, Settings } from "lucide-react";

export function RoleUsersTab({ role }) {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [selectedUsers, setSelectedUsers] = useState(new Set());
  const [selectedUser, setSelectedUser] = useState(null);
  const [modalOpen, setModalOpen] = useState(false);
  const [bulkModalOpen, setBulkModalOpen] = useState(false);

  useEffect(() => {
    fetchUsers();
  }, [role.id]);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const response = await userPermissionService.getUsersByRole(role.id, {
        limit: 100,
        search,
      });

      if (response?.success && response.data?.users) {
        setUsers(response.data.users);
      } else {
        setUsers([]);
      }
    } catch (error) {
      const errorMsg =
        error.response?.data?.message ||
        error.message ||
        "Không thể tải danh sách users";
      toast.error(errorMsg);
      setUsers([]);
    } finally {
      setLoading(false);
    }
  };

  const handleSearch = () => {
    fetchUsers();
  };

  const handleToggleUser = (userId) => {
    setSelectedUsers((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(userId)) {
        newSet.delete(userId);
      } else {
        newSet.add(userId);
      }
      return newSet;
    });
  };

  const handleSelectAll = () => {
    setSelectedUsers(new Set(users.map((u) => u.id)));
  };

  const handleDeselectAll = () => {
    setSelectedUsers(new Set());
  };

  const handleManageUser = (user) => {
    setSelectedUser(user);
    setModalOpen(true);
  };

  const handleBulkManage = () => {
    if (selectedUsers.size === 0) {
      toast.error("Vui lòng chọn ít nhất 1 user");
      return;
    }
    setBulkModalOpen(true);
  };

  const getInitials = (email, fullName) => {
    if (fullName) {
      return fullName
        .split(" ")
        .map((n) => n[0])
        .join("")
        .toUpperCase()
        .slice(0, 2);
    }
    return email.slice(0, 2).toUpperCase();
  };

  if (loading) {
    return (
      <div className="space-y-4 py-4">
        {[...Array(5)].map((_, i) => (
          <div
            key={i}
            className="flex items-center gap-3 p-4 border border-black"
          >
            <Skeleton className="h-10 w-10 border border-gray-300" />
            <div className="flex-1">
              <Skeleton className="h-4 w-48 mb-2 border border-gray-300" />
              <Skeleton className="h-3 w-32 border border-gray-300" />
            </div>
          </div>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-4 pb-4">
      <div className="flex items-center gap-3">
        <div className="relative flex-1">
          <div className="absolute left-0 top-0 h-full w-10 bg-black flex items-center justify-center text-white">
            <Search className="h-4 w-4" />
          </div>
          <Input
            placeholder="TÌM USER THEO EMAIL HOẶC TÊN..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && handleSearch()}
            className="pl-12 h-10 rounded-none border border-black bg-white focus-visible:ring-0 focus-visible:border-black focus:bg-yellow-50 uppercase text-xs font-mono"
          />
        </div>
        <Button
          onClick={handleSearch}
          variant="outline"
          className="h-10 rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
        >
          TÌM
        </Button>
      </div>

      {selectedUsers.size > 0 && (
        <div className="flex items-center justify-between p-4 bg-[#F3E600]/20 border-2 border-[#F3E600]">
          <p className="text-xs font-bold text-black uppercase tracking-wider font-mono">
            ĐÃ CHỌN {selectedUsers.size} USER(S)
          </p>
          <div className="flex gap-2">
            <Button
              size="sm"
              onClick={handleBulkManage}
              className="bg-black hover:bg-[#F3E600] hover:text-black text-white rounded-none border border-black uppercase text-xs font-bold"
            >
              <UserCog className="h-3 w-3 mr-2" />
              CHỈNH QUYỀN HÀNG LOẠT
            </Button>
            <Button
              size="sm"
              variant="outline"
              onClick={handleDeselectAll}
              className="bg-white border border-black text-black hover:bg-gray-100 rounded-none uppercase text-xs font-bold"
            >
              BỎ CHỌN
            </Button>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between border-b border-black pb-2">
        <p className="text-xs font-mono font-bold text-black uppercase tracking-wider">
          {users.length} USER(S)
        </p>
        <Button
          size="sm"
          variant="ghost"
          onClick={handleSelectAll}
          disabled={selectedUsers.size === users.length}
          className="text-black hover:bg-gray-100 border border-black rounded-none uppercase text-xs font-bold h-8"
        >
          CHỌN TẤT CẢ
        </Button>
      </div>

      {users.length === 0 ? (
        <div className="text-center py-12 text-gray-500 bg-white border border-black border-dashed">
          <Users className="h-12 w-12 mx-auto mb-3 opacity-20" />
          <p className="uppercase font-mono text-xs">
            CHƯA CÓ USER NÀO TRONG VAI TRÒ NÀY
          </p>
        </div>
      ) : (
        <div className="space-y-3">
          {users.map((user) => (
            <div
              key={user.id}
              className="group flex items-center gap-3 p-4 bg-white border border-black hover:shadow-hard transition-all hover:border-l-4 hover:border-l-[#F3E600]"
            >
              <Checkbox
                checked={selectedUsers.has(user.id)}
                onCheckedChange={() => handleToggleUser(user.id)}
                className="data-[state=checked]:bg-[#F3E600] data-[state=checked]:border-black data-[state=checked]:text-black rounded-none border-2"
              />
              <Avatar className="h-10 w-10 border-2 border-black rounded-none">
                <AvatarImage src={user.avatar} />
                <AvatarFallback className="bg-gray-100 text-black font-bold rounded-none">
                  {getInitials(user.email, user.fullName)}
                </AvatarFallback>
              </Avatar>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <p className="font-bold text-black truncate uppercase text-sm tracking-tight">
                    {user.fullName || user.email}
                  </p>
                  {user.customPermissionCount > 0 && (
                    <Badge
                      variant="secondary"
                      className="text-[10px] bg-[#F3E600] text-black border border-black rounded-none uppercase font-mono"
                    >
                      +{user.customPermissionCount} CUSTOM
                    </Badge>
                  )}
                  <Badge
                    variant={
                      user.status === "active" ? "default" : "destructive"
                    }
                    className={
                      user.status === "active"
                        ? "text-[10px] bg-black text-white border border-black rounded-none uppercase font-mono"
                        : "text-[10px] bg-red-500 text-white border border-black rounded-none uppercase font-mono"
                    }
                  >
                    {user.status}
                  </Badge>
                </div>
                <p className="text-xs text-gray-500 truncate font-mono">
                  {user.email}
                </p>
              </div>
              <Button
                size="sm"
                variant="outline"
                onClick={() => handleManageUser(user)}
                className="opacity-0 group-hover:opacity-100 transition-opacity rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
              >
                <Settings className="h-3 w-3 mr-2" />
                QUẢN LÝ
              </Button>
            </div>
          ))}
        </div>
      )}

      <UserPermissionModal
        open={modalOpen}
        onOpenChange={setModalOpen}
        user={selectedUser}
        role={role}
        onUpdated={fetchUsers}
      />

      <UserPermissionModal
        open={bulkModalOpen}
        onOpenChange={setBulkModalOpen}
        userIds={Array.from(selectedUsers)}
        role={role}
        onUpdated={() => {
          fetchUsers();
          setSelectedUsers(new Set());
        }}
        isBulk
      />
    </div>
  );
}

import { useState, useEffect, useMemo } from "react";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/Dialog";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/Label";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Skeleton } from "@/components/ui/skeleton";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Progress } from "@/components/ui/progress";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { PermissionCheckbox } from "./permission-checkbox";
import { userPermissionService } from "@/apis/userPermissionService";
import { permissionService } from "@/apis/permissionService";
import { MODULE_DISPLAY_NAMES } from "@/constants/permissions";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import {
  Search,
  CheckCircle,
  XCircle,
  ChevronDown,
  Save,
  RefreshCw,
  SearchX,
  UserCog,
  Info,
  RotateCcw,
} from "lucide-react";

export function UserPermissionModal({
  open,
  onOpenChange,
  user,
  userIds,
  role,
  onUpdated,
  isBulk = false,
}) {
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [allPermissions, setAllPermissions] = useState({});
  const [selectedPermissions, setSelectedPermissions] = useState(new Set());
  const [initialPermissions, setInitialPermissions] = useState(new Set());
  const [rolePermissions, setRolePermissions] = useState(new Set());
  const [search, setSearch] = useState("");
  const [moduleFilter, setModuleFilter] = useState("all");
  const [expandedModules, setExpandedModules] = useState(new Set());

  useEffect(() => {
    if (open && (user || isBulk)) {
      fetchData();
    }
  }, [open, user, userIds]);

  const fetchData = async () => {
    try {
      setLoading(true);

      // Lấy tất cả permissions
      const permissionsResponse =
        await permissionService.getPermissionsByModule(false);

      if (!permissionsResponse || !permissionsResponse.permissions) {
        throw new Error("Không thể tải danh sách quyền");
      }

      setAllPermissions(permissionsResponse.permissions);

      // Lấy quyền của user (nếu single mode)
      if (!isBulk && user) {
        const userPermsResponse =
          await userPermissionService.getUserPermissions(user.id);

        if (userPermsResponse && userPermsResponse.permissions) {
          const allUserPermissions = new Set(); // TẤT CẢ quyền user có
          const roleOnlyPermissions = new Set(); // Quyền CHỈ từ role (để hiển thị badge)

          Object.values(userPermsResponse.permissions).forEach((perms) => {
            perms.forEach((p) => {
              allUserPermissions.add(p.id); // Thêm tất cả vào selected
              if (p.source === "role" && !p.hasBothSources) {
                roleOnlyPermissions.add(p.id); // Badge "Từ vai trò"
              }
            });
          });

          setSelectedPermissions(allUserPermissions);
          setInitialPermissions(new Set(allUserPermissions));
          setRolePermissions(roleOnlyPermissions); // Chỉ để hiển thị badge
        }
      } else {
        // Bulk mode: start with empty
        setSelectedPermissions(new Set());
        setInitialPermissions(new Set());
        setRolePermissions(new Set());
      }

      const modules = Object.keys(permissionsResponse.permissions);
      setExpandedModules(new Set(modules.slice(0, 3)));
    } catch (error) {
      console.error("Lỗi khi tải dữ liệu:", error);
      toast.error("Không thể tải danh sách quyền");
    } finally {
      setLoading(false);
    }
  };

  const handleTogglePermission = (permissionId) => {
    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(permissionId)) {
        newSet.delete(permissionId);
      } else {
        newSet.add(permissionId);
      }
      return newSet;
    });
  };

  const handleToggleModule = (module) => {
    const modulePermissions = filteredPermissions[module] || [];
    const moduleIds = modulePermissions.map((p) => p.id);
    const allSelected = moduleIds.every((id) => selectedPermissions.has(id));

    setSelectedPermissions((prev) => {
      const newSet = new Set(prev);
      if (allSelected) {
        moduleIds.forEach((id) => newSet.delete(id));
      } else {
        moduleIds.forEach((id) => newSet.add(id));
      }
      return newSet;
    });
  };

  const handleSave = async () => {
    try {
      setSaving(true);
      const permissionIds = Array.from(selectedPermissions);

      if (isBulk) {
        await userPermissionService.bulkUpdateUserPermissions(
          userIds,
          permissionIds,
        );
        toast.success(`Cập nhật quyền cho ${userIds.length} users thành công`);
      } else {
        await userPermissionService.updateUserPermissions(
          user.id,
          permissionIds,
        );
        toast.success("Cập nhật quyền user thành công");
      }

      setInitialPermissions(new Set(selectedPermissions));

      if (onUpdated) {
        onUpdated();
      }

      onOpenChange(false);
    } catch (error) {
      console.error("Lỗi khi cập nhật quyền:", error);
      toast.error(error.response?.data?.message || "Không thể cập nhật quyền");
    } finally {
      setSaving(false);
    }
  };

  const filteredPermissions = useMemo(() => {
    let result = { ...allPermissions };

    if (moduleFilter !== "all") {
      result = { [moduleFilter]: allPermissions[moduleFilter] || [] };
    }

    if (search.trim()) {
      const lowerSearch = search.toLowerCase();
      const filtered = {};

      Object.entries(result).forEach(([module, perms]) => {
        const matched = perms.filter(
          (p) =>
            p.name.toLowerCase().includes(lowerSearch) ||
            p.displayName.toLowerCase().includes(lowerSearch),
        );
        if (matched.length > 0) {
          filtered[module] = matched;
        }
      });

      result = filtered;
    }

    return result;
  }, [allPermissions, moduleFilter, search]);

  const stats = useMemo(() => {
    let totalFiltered = 0;
    let selectedFiltered = 0;

    Object.values(filteredPermissions).forEach((perms) => {
      totalFiltered += perms.length;
      selectedFiltered += perms.filter((p) =>
        selectedPermissions.has(p.id),
      ).length;
    });

    return {
      total: totalFiltered,
      selected: selectedFiltered,
      percentage:
        totalFiltered > 0 ? (selectedFiltered / totalFiltered) * 100 : 0,
    };
  }, [filteredPermissions, selectedPermissions]);

  const hasChanges = useMemo(() => {
    if (selectedPermissions.size !== initialPermissions.size) return true;
    for (const id of selectedPermissions) {
      if (!initialPermissions.has(id)) return true;
    }
    return false;
  }, [selectedPermissions, initialPermissions]);

  const toggleModuleExpand = (module) => {
    setExpandedModules((prev) => {
      const newSet = new Set(prev);
      if (newSet.has(module)) {
        newSet.delete(module);
      } else {
        newSet.add(module);
      }
      return newSet;
    });
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl h-[90vh] flex flex-col p-0 bg-white border-2 border-black rounded-none shadow-hard">
        <DialogHeader className="p-6 border-b-2 border-black">
          <DialogTitle className="text-xl flex items-center gap-3 font-bold uppercase tracking-wider">
            <div className="h-8 w-8 bg-black text-white flex items-center justify-center">
              <UserCog className="h-5 w-5" />
            </div>
            {isBulk
              ? `CHỈNH QUYỀN CHO ${userIds?.length || 0} USERS`
              : `CHỈNH QUYỀN - ${user?.fullName || user?.email}`}
          </DialogTitle>
          <DialogDescription className="text-gray-500 mt-1 font-mono text-xs uppercase">
            {isBulk
              ? "QUYỀN ĐƯỢC THÊM SẼ ÁP DỤNG CHO TẤT CẢ USERS"
              : `VAI TRÒ: ${role?.displayName}. QUYỀN CUSTOM SẼ OVERRIDE QUYỀN TỪ ROLE.`}
          </DialogDescription>
        </DialogHeader>

        {loading ? (
          <div className="space-y-4 p-6">
            <Skeleton className="h-10 w-full border border-black" />
            <Skeleton className="h-10 w-full border border-black" />
            <Skeleton className="h-40 w-full border border-black" />
          </div>
        ) : (
          <>
            <div className="space-y-4 p-6 pb-0">
              {!isBulk && rolePermissions.size > 0 && (
                <Alert className="bg-[#F3E600]/10 border-2 border-[#F3E600] text-black rounded-none">
                  <Info className="h-4 w-4 text-black" />
                  <AlertDescription className="text-xs font-mono uppercase">
                    {rolePermissions.size} QUYỀN CÓ BADGE "ROLE" LÀ QUYỀN MẶC
                    ĐỊNH. BẠN CÓ THỂ BỎ CHỌN HOẶC THÊM QUYỀN KHÁC.
                  </AlertDescription>
                </Alert>
              )}

              <div className="flex flex-col sm:flex-row items-center gap-3">
                <div className="relative flex-1 w-full">
                  <div className="absolute left-0 top-0 h-full w-10 bg-black flex items-center justify-center text-white">
                    <Search className="h-4 w-4" />
                  </div>
                  <Input
                    placeholder="TÌM KIẾM QUYỀN..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="pl-12 h-10 rounded-none border border-black bg-white focus-visible:ring-0 focus-visible:border-black focus:bg-yellow-50 uppercase text-xs font-mono"
                  />
                </div>
                <Select value={moduleFilter} onValueChange={setModuleFilter}>
                  <SelectTrigger className="w-full sm:w-[200px] h-10 rounded-none border border-black bg-white uppercase text-xs font-bold">
                    <SelectValue placeholder="LỌC MODULE" />
                  </SelectTrigger>
                  <SelectContent className="rounded-none border-2 border-black bg-white">
                    <SelectItem
                      value="all"
                      className="uppercase font-mono text-xs"
                    >
                      TẤT CẢ MODULES
                    </SelectItem>
                    {Object.keys(allPermissions).map((module) => (
                      <SelectItem
                        key={module}
                        value={module}
                        className="uppercase font-mono text-xs"
                      >
                        {MODULE_DISPLAY_NAMES[module] || module}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="flex flex-col sm:flex-row items-center justify-between gap-4 bg-white p-4 border border-black">
                <div className="space-y-2 w-full sm:w-auto">
                  <div className="flex items-center gap-3 text-xs font-bold text-black uppercase tracking-wider">
                    <span className="font-mono">
                      ĐÃ CHỌN: {stats.selected} / {stats.total}
                    </span>
                    <span className="bg-[#F3E600] text-black px-2 py-0.5 font-mono">
                      {Math.round(stats.percentage)}%
                    </span>
                  </div>
                  <div className="w-full sm:w-[200px] h-1 bg-gray-200 border border-gray-300">
                    <div
                      className="h-full bg-[#F3E600] transition-all duration-300"
                      style={{ width: `${stats.percentage}%` }}
                    />
                  </div>
                </div>
                <div className="flex gap-2 w-full sm:w-auto">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => {
                      const allIds = new Set();
                      Object.values(filteredPermissions).forEach((perms) => {
                        perms.forEach((p) => allIds.add(p.id));
                      });
                      setSelectedPermissions(allIds);
                    }}
                    disabled={stats.selected === stats.total}
                    className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
                  >
                    <CheckCircle className="h-3 w-3 mr-2" />
                    CHỌN TẤT
                  </Button>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={() => setSelectedPermissions(new Set())}
                    disabled={stats.selected === 0}
                    className="flex-1 sm:flex-none rounded-none border border-black hover:bg-black hover:text-white uppercase text-xs font-bold"
                  >
                    <XCircle className="h-3 w-3 mr-2" />
                    BỎ CHỌN
                  </Button>
                </div>
              </div>
            </div>

            <ScrollArea className="flex-1 px-6 py-2 h-[calc(90vh-450px)]">
              <div className="space-y-3 pb-4">
                {Object.keys(filteredPermissions).length === 0 ? (
                  <div className="text-center py-12 text-gray-500 bg-white border border-black border-dashed">
                    <SearchX className="h-12 w-12 mx-auto mb-2 opacity-30" />
                    <p className="uppercase font-mono text-xs">
                      KHÔNG TÌM THẤY QUYỀN
                    </p>
                  </div>
                ) : (
                  Object.entries(filteredPermissions).map(
                    ([module, permissions]) => {
                      const moduleSelected = permissions.filter((p) =>
                        selectedPermissions.has(p.id),
                      ).length;
                      const moduleTotal = permissions.length;
                      const isExpanded = expandedModules.has(module);

                      return (
                        <div
                          key={module}
                          className="border border-black overflow-hidden transition-all hover:shadow-hard"
                        >
                          <div
                            className="flex items-center justify-between p-4 bg-white cursor-pointer select-none hover:bg-gray-50 border-l-4 border-l-transparent hover:border-l-[#F3E600] transition-all"
                            onClick={() => toggleModuleExpand(module)}
                          >
                            <div className="flex items-center gap-3">
                              <div onClick={(e) => e.stopPropagation()}>
                                <Checkbox
                                  checked={
                                    moduleSelected === moduleTotal &&
                                    moduleTotal > 0
                                      ? true
                                      : moduleSelected > 0
                                        ? "indeterminate"
                                        : false
                                  }
                                  onCheckedChange={() =>
                                    handleToggleModule(module)
                                  }
                                  className="data-[state=checked]:bg-[#F3E600] data-[state=checked]:border-black data-[state=checked]:text-black rounded-none border-2"
                                />
                              </div>
                              <div className="flex items-center gap-3">
                                <div className="h-8 w-1 bg-black"></div>
                                <div>
                                  <Label className="font-bold text-black text-sm cursor-pointer uppercase tracking-tight">
                                    {MODULE_DISPLAY_NAMES[module] || module}
                                  </Label>
                                  <p className="text-xs text-gray-500 font-mono mt-0.5 uppercase">
                                    {moduleSelected}/{moduleTotal} QUYỀN
                                  </p>
                                </div>
                              </div>
                            </div>
                            <div className="flex items-center gap-3">
                              <Badge
                                variant="secondary"
                                className="bg-black text-white rounded-none px-2.5 py-1 font-mono text-xs uppercase"
                              >
                                {module}
                              </Badge>
                              <ChevronDown
                                className={cn(
                                  "h-4 w-4 text-black transition-transform duration-200",
                                  isExpanded ? "rotate-180" : "",
                                )}
                              />
                            </div>
                          </div>

                          {isExpanded && (
                            <div className="p-4 space-y-2 bg-gray-50 border-t-2 border-black">
                              {permissions.map((permission) => {
                                const isInherited = rolePermissions.has(
                                  permission.id,
                                );
                                const isCustomSelected =
                                  selectedPermissions.has(permission.id);
                                const isChecked =
                                  isInherited || isCustomSelected;

                                return (
                                  <PermissionCheckbox
                                    key={permission.id}
                                    permission={permission}
                                    checked={isChecked}
                                    onCheckedChange={() =>
                                      handleTogglePermission(permission.id)
                                    }
                                    isInherited={isInherited}
                                    showSource={!isBulk}
                                  />
                                );
                              })}
                            </div>
                          )}
                        </div>
                      );
                    },
                  )
                )}
              </div>
            </ScrollArea>

            <DialogFooter className="flex items-center justify-between p-6 border-t-2 border-black">
              <div>
                {!isBulk && rolePermissions.size > 0 && (
                  <Button
                    variant="ghost"
                    size="sm"
                    onClick={() =>
                      setSelectedPermissions(new Set(rolePermissions))
                    }
                    disabled={saving}
                    className="text-black hover:bg-gray-100 border border-black rounded-none uppercase text-xs font-bold"
                  >
                    <RotateCcw className="h-3 w-3 mr-2" />
                    ĐẶT LẠI MẶC ĐỊNH
                  </Button>
                )}
              </div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={() => onOpenChange(false)}
                  className="rounded-none border border-black hover:bg-gray-100 uppercase text-xs font-bold"
                >
                  HỦY
                </Button>
                <Button
                  onClick={handleSave}
                  disabled={!hasChanges || saving}
                  className="rounded-none bg-black hover:bg-[#F3E600] hover:text-black text-white border border-black shadow-hard uppercase text-xs font-bold"
                >
                  {saving ? (
                    <span className="flex items-center gap-2">
                      <RefreshCw className="h-3 w-3 animate-spin" />
                      ĐANG LƯU...
                    </span>
                  ) : (
                    <span className="flex items-center gap-2">
                      <Save className="h-3 w-3" />
                      LƯU THAY ĐỔI
                    </span>
                  )}
                </Button>
              </div>
            </DialogFooter>
          </>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/Button";
import { Input } from "@/components/ui/Input";
import { Label } from "@/components/ui/Label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/Dialog";
import { Checkbox } from "@/components/ui/checkbox";
import useTagStore from "@/stores/tagStore";
import { useToast } from "@/hooks/use-toast";
import { TAG_TYPES, TAG_COLOR_PRESETS } from "@/constants/tagConstants";

/**
 * TAG FORM DIALOG
 * Form tạo/sửa tag
 */

export default function TagFormDialog({ open, onClose, tag }) {
  const { createTag, updateTag, fetchTags } = useTagStore();
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    name: "",
    slug: "",
    tagType: "general",
    icon: "",
    color: "#6B7280",
    isActive: true,
  });

  useEffect(() => {
    if (tag) {
      setFormData({
        name: tag.name || "",
        slug: tag.slug || "",
        tagType: tag.tagType || "general",
        icon: tag.icon || "",
        color: tag.color || "#6B7280",
        isActive: tag.isActive !== undefined ? tag.isActive : true,
      });
    } else {
      setFormData({
        name: "",
        slug: "",
        tagType: "general",
        icon: "",
        color: "#6B7280",
        isActive: true,
      });
    }
  }, [tag, open]);

  const handleChange = (field, value) => {
    setFormData((prev) => ({ ...prev, [field]: value }));

    // Auto-generate slug from name
    if (field === "name" && !tag) {
      const slug = value
        .toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/đ/g, "d")
        .replace(/[^a-z0-9\s-]/g, "")
        .trim()
        .replace(/\s+/g, "-");
      setFormData((prev) => ({ ...prev, slug }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      if (tag) {
        await updateTag(tag.id, formData);
        toast({
          title: "Success",
          description: "Tag updated successfully",
        });
      } else {
        await createTag(formData);
        toast({
          title: "Success",
          description: "Tag created successfully",
        });
      }
      await fetchTags();
      onClose();
    } catch (error) {
      toast({
        variant: "destructive",
        title: "Error",
        description: error.response?.data?.message || error.message,
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-xl">
        <DialogHeader>
          <DialogTitle>{tag ? "Edit Tag" : "Add Tag"}</DialogTitle>
          <DialogDescription>
            {tag ? "Update tag information" : "Create a new tag"}
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          {/* Name & Slug */}
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="name">
                Name <span className="text-destructive">*</span>
              </Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => handleChange("name", e.target.value)}
                placeholder="e.g. Giá rẻ"
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="slug">
                Slug <span className="text-destructive">*</span>
              </Label>
              <Input
                id="slug"
                value={formData.slug}
                onChange={(e) => handleChange("slug", e.target.value)}
                placeholder="e.g. gia-re"
                required
              />
            </div>
          </div>

          {/* Tag Type */}
          <div className="space-y-2">
            <Label htmlFor="tagType">
              Tag Type <span className="text-destructive">*</span>
            </Label>
            <Select
              value={formData.tagType}
              onValueChange={(val) => handleChange("tagType", val)}
            >
              <SelectTrigger>
                <SelectValue placeholder="Select tag type" />
              </SelectTrigger>
              <SelectContent>
                {Object.entries(TAG_TYPES).map(([value, label]) => (
                  <SelectItem key={value} value={value}>
                    {label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          {/* Color */}
          <div className="space-y-2">
            <Label htmlFor="color">Color</Label>
            <div className="flex gap-2">
              <Input
                id="color"
                type="color"
                value={formData.color}
                onChange={(e) => handleChange("color", e.target.value)}
                className="w-20 h-10"
              />
              <div className="flex flex-wrap gap-1 flex-1">
                {TAG_COLOR_PRESETS.map((color) => (
                  <button
                    key={color}
                    type="button"
                    className="w-8 h-8 rounded border-2 hover:scale-110 transition-transform"
                    style={{
                      backgroundColor: color,
                      borderColor:
                        formData.color === color ? "#000" : "transparent",
                    }}
                    onClick={() => handleChange("color", color)}
                  />
                ))}
              </div>
            </div>
          </div>

          {/* Icon (Optional) */}
          <div className="space-y-2">
            <Label htmlFor="icon">Icon (Optional)</Label>
            <Input
              id="icon"
              value={formData.icon}
              onChange={(e) => handleChange("icon", e.target.value)}
              placeholder="Lucide icon name"
            />
          </div>

          {/* Active Status */}
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-2">
              <Checkbox
                id="isActive"
                checked={formData.isActive}
                onCheckedChange={(checked) => handleChange("isActive", checked)}
              />
              <div className="space-y-0.5">
                <Label htmlFor="isActive" className="cursor-pointer">
                  Active Status
                </Label>
                <p className="text-xs text-muted-foreground">
                  Inactive tags won't be shown in filters
                </p>
              </div>
            </div>
          </div>

          <DialogFooter>
            <Button
              type="button"
              variant="outline"
              onClick={onClose}
              disabled={loading}
            >
              Cancel
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Saving..." : tag ? "Update" : "Create"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva } from "class-variance-authority";
import Loader2 from "lucide-react/dist/esm/icons/loader-2";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground hover:bg-destructive/90",
        outline:
          "border border-input bg-background hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-9 rounded-md px-3",
        lg: "h-11 rounded-md px-8",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

const Button = React.forwardRef(
  (
    {
      className,
      variant,
      size,
      asChild = false,
      loading = false,
      children,
      disabled,
      ...props
    },
    ref,
  ) => {
    const Comp = asChild ? Slot : "button";

    // Khi asChild=true, Slot chỉ chấp nhận 1 child, không thể thêm Loader
    if (asChild) {
      return (
        <Comp
          className={cn(buttonVariants({ variant, size, className }))}
          ref={ref}
          {...props}
        >
          {children}
        </Comp>
      );
    }

    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        disabled={disabled || loading}
        {...props}
      >
        {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
        {children}
      </Comp>
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

