      UPDATE: "bg-blue-100 text-blue-700",
      DELETE: "bg-red-100 text-red-700",
      UPDATE_ROLE: "bg-orange-100 text-orange-700",
      UPDATE_PERMISSIONS: "bg-purple-100 text-purple-700",
