  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { PRICE_RANGE_LABELS } from "@/constants/constants";
import { usePermission } from "@/hooks/usePermission";
import { Textarea } from "@/components/ui/textarea";
import TimStatsCard from "@/components/admin/TimStatsCard";
import BusinessDetailModal from "@/components/admin/BusinessDetailModal";

/**
 * PLACE LIST PAGE - T.I.M STYLE OVERHAUL (VIETNAMESE)
 */

const PlaceListPage = ({
  initialStatus = "all",
  lockStatusFilter = false,
  pageTitle = "QUẢN LÝ ĐỊA ĐIỂM",
  pageMeta = "KIỂM SOÁT VÀ ĐIỀU PHỐI DỮ LIỆU",
  moderationMode = false,
  allowCreate = true,
}) => {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const { toast } = useToast();
  const { hasPermission } = usePermission();
  const canModeratePlaces =
    hasPermission("places.approve") || hasPermission("places.reject");
  const canFeaturePlaces = hasPermission("places.feature");

  const {
    places,
    loading,
    pagination,
    fetchPlaces,
    deletePlace,
    updatePlaceStatus,
    approvePlace,
    rejectPlace,
    toggleFeature,
  } = usePlaceStore();

  const { categories, fetchCategories } = useCategoryStore();

  const [selectedPlace, setSelectedPlace] = useState(null);
  const [detailDialogOpen, setDetailDialogOpen] = useState(false);
  const [viewBusinessId, setViewBusinessId] = useState(null);
  const [viewMode, setViewMode] = useState("grid"); // grid | list
  const searchDebounceRef = useRef(null);
  const [moderationDialog, setModerationDialog] = useState({
    open: false,
    place: null,
    action: "approved",
    comment: "",
  });

  // Initialize from URL or defaults
  const [filters, setFilters] = useState({
    search: searchParams.get("search") || "",
    categoryId: searchParams.get("categoryId") || "",
    districtId: searchParams.get("districtId") || "",
    businessId: searchParams.get("businessId") || "",
    status: searchParams.get("status") || initialStatus,
    priceRange: searchParams.get("priceRange") || "",
    page: parseInt(searchParams.get("page")) || 1,
    limit: parseInt(searchParams.get("limit")) || 12,
  });

  // Sync from URL to State
  useEffect(() => {
    const newFilters = {
      search: searchParams.get("search") || "",
      categoryId: searchParams.get("categoryId") || "",
      districtId: searchParams.get("districtId") || "",
      businessId: searchParams.get("businessId") || "",
      status: searchParams.get("status") || initialStatus,
      priceRange: searchParams.get("priceRange") || "",
      page: parseInt(searchParams.get("page")) || 1,
      limit: parseInt(searchParams.get("limit")) || 12,
    };
    setFilters(newFilters);
  }, [searchParams, initialStatus]);

  // Load data when filters change
  useEffect(() => {
    const apiFilters = { ...filters };
    if (apiFilters.status === "all") apiFilters.status = "";
    if (apiFilters.categoryId === "all") apiFilters.categoryId = "";
    if (apiFilters.districtId === "all") apiFilters.districtId = "";
    if (!apiFilters.businessId) delete apiFilters.businessId;

    fetchPlaces(apiFilters);
  }, [filters]);

  useEffect(() => {
    if (categories.length === 0) fetchCategories();
  }, [categories.length]);

  const updateURL = (newFilters) => {
    const params = {};
    if (newFilters.search) params.search = newFilters.search;
    if (newFilters.categoryId && newFilters.categoryId !== "all")
      params.categoryId = newFilters.categoryId;
    if (newFilters.districtId && newFilters.districtId !== "all")
      params.districtId = newFilters.districtId;
    if (newFilters.status && newFilters.status !== "all")
      params.status = newFilters.status;
    if (newFilters.priceRange) params.priceRange = newFilters.priceRange;
    if (newFilters.businessId) params.businessId = newFilters.businessId;
    if (newFilters.page > 1) params.page = newFilters.page.toString();
    if (newFilters.limit !== 12) params.limit = newFilters.limit.toString();
    setSearchParams(params);
  };

  const handleSearch = (e) => {
    const value = e.target.value;
    if (searchDebounceRef.current) {
      clearTimeout(searchDebounceRef.current);
    }
    searchDebounceRef.current = setTimeout(() => {
      const newFilters = { ...filters, search: value, page: 1 };
      setFilters(newFilters);
      updateURL(newFilters);
    }, 350);
  };

  const onSearchKey = (e) => {
    if (e.key === "Enter") {
      if (searchDebounceRef.current) {
        clearTimeout(searchDebounceRef.current);
      }
      const newFilters = { ...filters, search: e.target.value, page: 1 };
      setFilters(newFilters);
      updateURL(newFilters);
    }
  };

  useEffect(() => {
    return () => {
      if (searchDebounceRef.current) clearTimeout(searchDebounceRef.current);
    };
  }, []);

  const handleFilterChange = (key, value) => {
    const newFilters = { ...filters, [key]: value, page: 1 };
    setFilters(newFilters);
    updateURL(newFilters);
  };

  const handleCreate = () => {
    navigate("/admin/places/new");
  };

  const handleViewDetails = (place) => {
    setSelectedPlace(place);
    setDetailDialogOpen(true);
  };

  const handleEdit = (place) => {
    setDetailDialogOpen(false);
    navigate(`/admin/places/edit/${place.id}`);
  };

  const handleDelete = async (place) => {
    if (!confirm(`XÁC NHẬN XÓA: "${place.name}"?`)) return;

    try {
      await deletePlace(place.id);
      toast({
        title: "HỆ THỐNG",
        description: "Đã xóa địa điểm khỏi cơ sở dữ liệu.",
        className: "bg-black text-white border border-primary font-mono",
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "LỖI",
        description: error.message || "Không thể thực hiện tác vụ.",
      });
    }
  };

  const handleStatusChange = async (place, newStatus) => {
    try {
      if (newStatus === "approved") {
        if (!hasPermission("places.approve")) {
          throw new Error("Bạn không có quyền duyệt địa điểm.");
        }
        await approvePlace(place.id);
      } else if (newStatus === "rejected") {
        if (!hasPermission("places.reject")) {
          throw new Error("Bạn không có quyền từ chối địa điểm.");
        }
        openModerationDialog(place, "rejected");
        return;
      } else {
        await updatePlaceStatus(place.id, newStatus);
      }
      toast({
        title: "TRẠNG THÁI",
        description: "Cập nhật trạng thái thành công.",
        className: "bg-black text-white border border-primary font-mono",
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "LỖI",
        description: error.message,
      });
    }
  };

  const openModerationDialog = (place, action) => {
    setModerationDialog({
      open: true,
      place,
      action,
      comment: "",
    });
  };

  const handleModerationConfirm = async () => {
    const place = moderationDialog.place;
    if (!place) return;

    const note = moderationDialog.comment?.trim() || "";
    if (moderationDialog.action === "rejected" && note.length < 10) {
      toast({
        variant: "destructive",
        title: "LỖI DỮ LIỆU",
        description: "Lý do từ chối phải có ít nhất 10 ký tự.",
      });
      return;
    }

    try {
      if (moderationDialog.action === "approved") {
        await approvePlace(place.id);
        toast({
          title: "DUYỆT THÀNH CÔNG",
          description: "Địa điểm đã được phê duyệt.",
          className: "bg-black text-white border border-primary font-mono",
        });
      } else {
        await rejectPlace(place.id, note);
        toast({
          title: "ĐÃ TỪ CHỐI",
          description: "Địa điểm đã được chuyển về trạng thái từ chối.",
          className: "bg-black text-white border border-primary font-mono",
        });
      }

      const refreshedFilters = { ...filters };
      if (refreshedFilters.status === "all") refreshedFilters.status = "";
      if (refreshedFilters.categoryId === "all")
        refreshedFilters.categoryId = "";
      if (refreshedFilters.districtId === "all")
        refreshedFilters.districtId = "";
      await fetchPlaces(refreshedFilters);

      setModerationDialog({
        open: false,
        place: null,
        action: "approved",
        comment: "",
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "LỖI",
        description: error.message || "Không thể cập nhật trạng thái duyệt.",
      });
    }
  };

  const handleToggleFeature = async (place) => {
    try {
      await toggleFeature(place.id);
      toast({
        title: "NỔI BẬT",
        description: place.isFeatured
          ? "Đã gỡ bỏ nổi bật."
          : "Đã thêm vào danh sách nổi bật.",
        className: "bg-black text-white border border-primary font-mono",
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "LỖI",
        description: error.message,
      });
    }
  };

  const placeStats = useMemo(() => {
    const total = places.length;
    const approved = places.filter((p) => p.status === "approved").length;
    const pending = places.filter((p) => p.status === "pending").length;
    const featured = places.filter((p) => p.isFeatured).length;
    return { total, approved, pending, featured };
  }, [places]);

  const getStatusBadge = (status) => {
    const statusConfig = {
      draft: {
        label: "DRAFT",
        className: "bg-gray-200 text-gray-700 border-2 border-gray-400",
      },
      pending: {
        label: "PENDING",
        className:
          "bg-yellow-400 text-black border-2 border-yellow-600 animate-pulse font-black",
      },
      approved: {
        label: "APPROVED",
        className: "bg-[#F3E600] text-black border-2 border-black font-black",
      },
      rejected: {
        label: "REJECTED",
        className: "bg-red-500 text-white border-2 border-red-700 font-black",
      },
      hidden: {
        label: "HIDDEN",
        className: "bg-gray-800 text-gray-300 border-2 border-gray-600",
      },
    };

    const config = statusConfig[status] || statusConfig.draft;
    return (
      <div
        className={`px-3 py-1.5 text-[10px] uppercase font-mono ${config.className} backdrop-blur-sm shadow-sm`}
      >
        {config.label}
      </div>
    );
  };

  return (
    <div className="min-h-screen p-8 bg-[#F4F4F4] relative font-sans">
      <div className="absolute inset-0 bg-grid-pattern bg-grid-20 opacity-30 pointer-events-none"></div>

      <div className="relative z-10 space-y-6 max-w-[1600px] mx-auto">
        {/* Header */}
        <div className="flex items-end justify-between border-b-2 border-black pb-6">
          <div className="flex items-center gap-6">
            <div className="accent-bar h-16"></div>
            <div>
              <h1 className="tim-title">{pageTitle}</h1>
              <div className="flex items-center gap-4 mt-2">
                <span className="tim-system bg-black text-white px-2 py-1">
                  DATABASE // PLACES
                </span>
                <p className="tim-meta">{pageMeta}</p>
              </div>
            </div>
          </div>
          {allowCreate && hasPermission("places.create") && (
            <Button
              onClick={handleCreate}
              className="h-12 bg-black text-white hover:bg-primary hover:text-black hover:shadow-hard transition-all tim-button rounded-none border border-black px-6"
            >
              <Plus className="mr-2 h-4 w-4" />
              KHỞI TẠO ĐỊA ĐIỂM
            </Button>
          )}
        </div>

        {/* Thống kê nhanh (theo dữ liệu trang / bộ lọc hiện tại) */}
        {!loading && (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <TimStatsCard
              title="TỔNG (TRANG)"
              value={placeStats.total}
              icon={MapPin}
              serial="PLC-001"
            />
            <TimStatsCard
              title="ĐÃ DUYỆT"
              value={placeStats.approved}
              icon={CheckCircle}
              serial="PLC-002"
              textColor="text-emerald-600"
            />
            <TimStatsCard
              title="CHỜ DUYỆT"
              value={placeStats.pending}
              icon={Activity}
              serial="PLC-003"
              textColor="text-amber-600"
            />
            <TimStatsCard
              title="NỔI BẬT"
              value={placeStats.featured}
              icon={Star}
              serial="PLC-004"
              color="bg-yellow-50"
            />
          </div>
        )}

        {/* Filter Bar */}
        <div className="bg-white border border-black p-4 flex flex-col md:flex-row gap-4 shadow-sm">
          {/* Search */}
          <div className="flex-1 flex shadow-sm">
            <div className="h-10 w-10 bg-black flex items-center justify-center text-white">
              <Search className="h-4 w-4" />
            </div>
            <input
              placeholder="TÌM KIẾM THEO TÊN, ĐỊA CHỈ [ENTER]..."
              value={filters.search}
              onChange={handleSearch}
              onKeyDown={onSearchKey}
              className="flex-1 h-10 px-4 border-y border-r border-black font-mono text-sm uppercase focus:outline-none focus:bg-yellow-50 placeholder:text-gray-400"
            />
          </div>

          {/* Filters */}
          <div className="flex gap-4 overflow-x-auto pb-2 md:pb-0">
            <Select
              value={filters.status || "all"}
              onValueChange={(val) => handleFilterChange("status", val)}
              disabled={lockStatusFilter}
            >
              <SelectTrigger className="w-[150px] h-10 rounded-none border-black font-mono text-xs uppercase bg-white">
                <SelectValue placeholder="TRẠNG THÁI" />
              </SelectTrigger>
              <SelectContent className="rounded-none border-black">
                <SelectItem value="all">TẤT CẢ</SelectItem>
                <SelectItem value="pending">CHỜ DUYỆT</SelectItem>
                <SelectItem value="approved">ĐÃ DUYỆT</SelectItem>
                <SelectItem value="draft">NHÁP</SelectItem>
                <SelectItem value="rejected">TỪ CHỐI</SelectItem>
              </SelectContent>
            </Select>

            <Select
              value={filters.categoryId || "all"}
              onValueChange={(val) => handleFilterChange("categoryId", val)}
            >
              <SelectTrigger className="w-[180px] h-10 rounded-none border-black font-mono text-xs uppercase bg-white">
                <SelectValue placeholder="DANH MỤC" />
              </SelectTrigger>
              <SelectContent className="rounded-none border-black">
                <SelectItem value="all">TẤT CẢ DANH MỤC</SelectItem>
                {categories.map((cat) => (
                  <SelectItem key={cat.id} value={cat.id.toString()}>
                    {cat.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <div className="border-l border-black pl-4 flex gap-2">
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setViewMode("grid")}
                className={`h-10 w-10 rounded-none border border-black ${viewMode === "grid" ? "bg-primary text-black" : "text-gray-400 hover:text-black"}`}
              >
                <GridIcon className="h-4 w-4" />
              </Button>
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setViewMode("list")}
                className={`h-10 w-10 rounded-none border border-black ${viewMode === "list" ? "bg-primary text-black" : "text-gray-400 hover:text-black"}`}
              >
                <List className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </div>

        {/* Content Grid */}
        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-12 h-12 border-4 border-black border-t-primary rounded-full animate-spin"></div>
            <div className="font-mono text-xs uppercase tracking-widest text-muted-foreground">
              LOADING DATA STREAM...
            </div>
          </div>
        ) : (
          <div
            className={
              viewMode === "grid"
                ? "grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6"
                : "space-y-2"
            }
          >
            {places.map((place) =>
              viewMode === "grid" ? (
                // GRID VIEW CARD - ENHANCED T.I.M STYLE
                <div
                  key={place.id}
                  className="relative group bg-white border-2 border-black transition-all hover:-translate-y-2 hover:shadow-[8px_8px_0px_0px_rgba(0,0,0,1)] overflow-hidden"
                >
                  {/* Grid Background Overlay */}
                  <div className="absolute inset-0 bg-grid-dots opacity-30 pointer-events-none"></div>

                  {/* Image Container */}
                  <div className="h-52 bg-gray-900 relative overflow-hidden border-b-2 border-black">
                    {place.images?.[0] ? (
                      <>
                        <img
                          src={place.images[0].imageData || place.images[0]}
                          className="w-full h-full object-cover grayscale-[0.7] group-hover:grayscale-0 group-hover:scale-110 transition-all duration-700"
                          alt={place.name}
                        />
                        {/* Accent Bar on Image */}
                        <div className="absolute bottom-0 left-0 w-1 h-full bg-[#F3E600] group-hover:w-2 transition-all"></div>
                      </>
                    ) : (
                      <div className="absolute inset-0 flex flex-col items-center justify-center bg-gradient-to-br from-gray-800 to-gray-900">
                        <MapPin className="h-12 w-12 text-gray-600 mb-2" />
                        <span className="font-mono text-xs text-gray-500 uppercase tracking-wider">
                          NO_IMAGE_DATA
                        </span>
                      </div>
                    )}

                    {/* Status & Featured Badges */}
                    <div className="absolute top-3 right-3 flex flex-col items-end gap-2">
                      {getStatusBadge(place.status)}
                      {place.isFeatured && (
                        <div className="bg-[#F3E600] border-2 border-black text-black px-2 py-1 text-[10px] uppercase font-black flex items-center gap-1">
                          <Star className="w-3 h-3 fill-black" /> FEATURED
                        </div>
                      )}
                    </div>

                    {/* ID Badge */}
                    <div className="absolute top-3 left-3 bg-black/80 backdrop-blur-sm border border-white/20 px-2 py-1">
                      <span className="font-mono text-[10px] text-white">
                        #{place.id}
                      </span>
                    </div>
                  </div>

                  {/* Content Section */}
                  <div className="p-5 relative bg-white">
                    {/* Title */}
                    <h3
                      className="font-black text-lg leading-tight uppercase mb-2 tracking-tight hover:text-[#F3E600] transition-colors cursor-pointer"
                      title={place.name}
                      onClick={() => handleViewDetails(place)}
                    >
                      {place.name.length > 30
                        ? `${place.name.substring(0, 30)  }...`
                        : place.name}
                    </h3>

                    {/* Meta Info */}
                    <div className="flex items-center gap-2 text-[10px] font-mono text-gray-500 mb-4 uppercase">
                      <span className="bg-gray-100 px-2 py-0.5 border border-gray-300">
                        {place.category?.name || "UNCATEGORIZED"}
                      </span>
                      <span className="text-gray-300">//</span>
                      <span
                        className="truncate max-w-[120px]"
                        title={place.district?.name}
                      >
                        {place.district?.name || "NO_DISTRICT"}
                      </span>
                    </div>

                    {/* Stats Grid - Enhanced */}
                    <div className="grid grid-cols-2 gap-3 border-t-2 border-black pt-4 mb-4">
                      <div className="text-center bg-gray-50 border border-gray-200 p-2">
                        <div className="text-[10px] text-gray-400 font-mono uppercase mb-1 tracking-wider">
                          <Eye className="w-3 h-3 inline mr-1" />
                          VIEWS
                        </div>
                        <div className="font-black text-xl tracking-tighter">
                          {place.viewCount || 0}
                        </div>
                      </div>
                      <div className="text-center bg-yellow-50 border border-yellow-200 p-2">
                        <div className="text-[10px] text-gray-400 font-mono uppercase mb-1 tracking-wider">
                          <Star className="w-3 h-3 inline mr-1" />
                          RATING
                        </div>
                        <div className="font-black text-xl tracking-tighter text-yellow-600">
                          {place.ratingAvg
                            ? parseFloat(place.ratingAvg).toFixed(1)
                            : "N/A"}
                        </div>
                      </div>
                    </div>

                    {/* Action Buttons - Tactical Style */}
                    <div className="flex gap-2">
                      <Button
                        size="sm"
                        className="flex-1 rounded-none border-2 border-black bg-white text-black hover:bg-[#F3E600] hover:border-black hover:shadow-[4px_4px_0px_0px_rgba(0,0,0,1)] uppercase font-black text-xs h-10 transition-all"
                        onClick={() => handleEdit(place)}
                      >
                        <Edit className="w-4 h-4 mr-1.5" /> EDIT
                      </Button>
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button
                            size="icon"
                            className="h-10 w-10 rounded-none border-2 border-black bg-black text-[#F3E600] hover:bg-[#F3E600] hover:text-black transition-all"
                          >
                            <MoreHorizontal className="w-5 h-5" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent
                          align="end"
                          className="rounded-none border border-black w-48 font-mono text-xs uppercase"
                        >
                          <DropdownMenuLabel>TÁC VỤ</DropdownMenuLabel>
                          <DropdownMenuSeparator />
                          <DropdownMenuItem
                            onClick={() => handleViewDetails(place)}
                            className="cursor-pointer hover:bg-gray-100"
                          >
                            <Info className="mr-2 h-3 w-3" /> CHI TIẾT
                          </DropdownMenuItem>
                          {canFeaturePlaces && (
                            <DropdownMenuItem
                              onClick={() => handleToggleFeature(place)}
                              className="cursor-pointer hover:bg-gray-100"
                            >
                              <Star className="mr-2 h-3 w-3" />{" "}
                              {place.isFeatured ? "GỠ NỔI BẬT" : "ĐẶT NỔI BẬT"}
                            </DropdownMenuItem>
                          )}

                          {place.status === "pending" && canModeratePlaces && (
                            <>
                              <DropdownMenuSeparator />
                              {hasPermission("places.approve") && (
                                <DropdownMenuItem
                                  onClick={() =>
                                    moderationMode
                                      ? openModerationDialog(place, "approved")
                                      : handleStatusChange(place, "approved")
                                  }
                                  className="text-green-600 hover:bg-green-50 cursor-pointer text-bold"
                                >
                                  <CheckCircle className="mr-2 h-3 w-3" /> DUYỆT
                                  NHANH
                                </DropdownMenuItem>
                              )}
                              {hasPermission("places.reject") && (
                                <DropdownMenuItem
                                  onClick={() =>
                                    moderationMode
                                      ? openModerationDialog(place, "rejected")
                                      : handleStatusChange(place, "rejected")
                                  }
                                  className="text-red-600 hover:bg-red-50 cursor-pointer text-bold"
                                >
                                  <XCircle className="mr-2 h-3 w-3" /> TỪ CHỐI
                                </DropdownMenuItem>
                              )}
                            </>
                          )}

                          {hasPermission("places.delete") && (
                            <>
                              <DropdownMenuSeparator />
                              <DropdownMenuItem
                                onClick={() => handleDelete(place)}
                                className="text-red-600 hover:bg-red-50 cursor-pointer"
                              >
                                <Trash2 className="mr-2 h-3 w-3" /> XÓA BỎ
                              </DropdownMenuItem>
                            </>
                          )}
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </div>
                  </div>
                </div>
              ) : (
                // LIST VIEW ROW
                <div
                  key={place.id}
                  className="flex items-center bg-white border border-gray-200 p-2 hover:border-black transition-colors group"
                >
                  <div className="w-12 h-12 bg-gray-200 mr-4 shrink-0 relative">
                    {place.images?.[0] && (
                      <img
                        src={place.images[0].imageData || place.images[0]}
                        className="w-full h-full object-cover"
                      />
                    )}
                  </div>
                  <div className="flex-1 min-w-0 grid grid-cols-12 items-center gap-4">
                    <div className="col-span-4">
                      <div className="font-bold text-sm uppercase truncate">
                        {place.name}
                      </div>
                      <div className="text-[10px] text-gray-500 font-mono">
                        {place.address}
                      </div>
                    </div>
                    <div className="col-span-2 text-[10px] font-mono uppercase bg-gray-50 p-1 text-center">
                      {place.category?.name}
                    </div>
                    <div className="col-span-3">
                      {getStatusBadge(place.status)}
                    </div>
                    <div className="col-span-3 text-right">
                      <Button
                        size="sm"
                        variant="ghost"
                        className="h-6 text-[10px] uppercase font-bold"
                        onClick={() => handleEdit(place)}
                      >
                        CHỈNH SỬA
                      </Button>
                    </div>
                  </div>
                </div>
              ),
            )}
          </div>
        )}

        {/* Empty State */}
        {!loading && places.length === 0 && (
          <div className="text-center py-20 border border-dashed border-black bg-white/50">
            <MapPin className="h-12 w-12 mx-auto mb-4 text-gray-300" />
            <h3 className="font-black text-xl uppercase mb-2">
              KHÔNG CÓ DỮ LIỆU
            </h3>
            <p className="font-mono text-xs text-muted-foreground mb-6 uppercase">
              HỆ THỐNG KHÔNG TÌM THẤY ĐỊA ĐIỂM NÀO KHỚP VỚI BỘ LỌC.
            </p>
            <Button
              onClick={handleCreate}
              className="rounded-none bg-black text-white px-8 font-bold uppercase hover:bg-primary hover:text-black"
            >
              KHỞI TẠO MỚI
            </Button>
          </div>
        )}

        {/* Pagination */}
        {pagination && pagination.totalPages > 1 && (
          <div className="flex items-center justify-between border-t border-black pt-4 font-mono text-xs uppercase">
            <div>
              TRANG {pagination.page} / {pagination.totalPages}
            </div>
            <div className="flex gap-2">
              <Button
                variant="outline"
                disabled={filters.page === 1}
                onClick={() => handleFilterChange("page", filters.page - 1)}
                className="rounded-none border-black h-8 hover:bg-black hover:text-white"
              >
                TRƯỚC
              </Button>
              <Button
                variant="outline"
                disabled={filters.page === pagination.totalPages}
                onClick={() => handleFilterChange("page", filters.page + 1)}
                className="rounded-none border-black h-8 hover:bg-black hover:text-white"
              >
                SAU
              </Button>
            </div>
          </div>
        )}
      </div>

      {/* Detail Dialog */}
      <Suspense
        fallback={
          <div className="flex items-center justify-center p-8">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
          </div>
        }
      >
        <PlaceDetailDialog
          place={selectedPlace}
          open={detailDialogOpen}
          onOpenChange={setDetailDialogOpen}
          onEdit={handleEdit}
          onDelete={handleDelete}
          onApprove={
            hasPermission("places.approve")
              ? (place) => approvePlace(place.id)
              : undefined
          }
          onReject={
            hasPermission("places.reject")
              ? (place) => openModerationDialog(place, "rejected")
              : undefined
          }
          onViewBusinessDetails={(id) => {
            setDetailDialogOpen(false);
            setViewBusinessId(id);
          }}
        />
      </Suspense>

      <BusinessDetailModal
        open={viewBusinessId != null}
        onOpenChange={(open) => {
          if (!open) setViewBusinessId(null);
        }}
        businessId={viewBusinessId}
      />

      <Dialog
        open={moderationDialog.open}
        onOpenChange={(open) =>
          setModerationDialog((prev) => ({ ...prev, open }))
        }
      >
        <DialogContent className="rounded-none border border-black bg-white sm:max-w-[560px]">
          <DialogHeader className="space-y-2">
            <DialogTitle className="font-black uppercase tracking-wide text-base">
              {moderationDialog.action === "approved"
                ? "XÁC NHẬN DUYỆT ĐỊA ĐIỂM"
                : "XÁC NHẬN TỪ CHỐI ĐỊA ĐIỂM"}
            </DialogTitle>
            <DialogDescription className="font-mono text-xs uppercase text-gray-500">
              {moderationDialog.place?.name || "ĐỊA ĐIỂM"}
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-2">
            <label className="font-mono text-[11px] uppercase text-gray-600">
              {moderationDialog.action === "approved"
                ? "GHI CHÚ (TÙY CHỌN)"
                : "LÝ DO TỪ CHỐI (BẮT BUỘC, TỐI THIỂU 10 KÝ TỰ)"}
            </label>
            <Textarea
              value={moderationDialog.comment}
              onChange={(e) =>
                setModerationDialog((prev) => ({
                  ...prev,
                  comment: e.target.value,
                }))
              }
              rows={4}
              placeholder={
                moderationDialog.action === "approved"
                  ? "Ví dụ: Nội dung đầy đủ, dữ liệu hợp lệ..."
                  : "Ví dụ: Thiếu thông tin địa chỉ, ảnh không phù hợp..."
              }
              className="rounded-none border-black focus-visible:ring-0 font-mono text-sm"
            />
          </div>

          <div className="flex justify-end gap-2 pt-2">
            <Button
              type="button"
              variant="outline"
              className="rounded-none border-black font-bold uppercase text-xs"
              onClick={() =>
                setModerationDialog({
                  open: false,
                  place: null,
                  action: "approved",
                  comment: "",
                })
              }
            >
              Hủy
            </Button>
            <Button
              type="button"
              className={`rounded-none border border-black font-bold uppercase text-xs ${
                moderationDialog.action === "approved"
                  ? "bg-green-600 hover:bg-green-700 text-white"
                  : "bg-red-600 hover:bg-red-700 text-white"
              }`}
              onClick={handleModerationConfirm}
            >
              {moderationDialog.action === "approved"
                ? "Xác nhận duyệt"
                : "Xác nhận từ chối"}
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
};

export default PlaceListPage;

import { useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import ArrowLeft from "lucide-react/dist/esm/icons/arrow-left";
import Check from "lucide-react/dist/esm/icons/check";
import Sparkles from "lucide-react/dist/esm/icons/sparkles";
import usePlaceStore from "@/stores/placeStore";
import { Button, Card } from "@/components/ui";
import { Progress } from "@/components/ui/progress";
import { useToast } from "@/hooks/use-toast";
import StepBasicInfo from "@/components/place/StepBasicInfo";
import StepDetails from "@/components/place/StepDetails";
import StepPreview from "@/components/place/StepPreview";
import { cn } from "@/lib/utils";

/**
 * PLACE WIZARD PAGE
 * Multi-step form để tạo/chỉnh sửa địa điểm
 */

const PlaceWizardPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { toast } = useToast();

  const {
    currentStep,
    totalSteps,
    loading,
    fetchPlaceById,
    loadPlaceIntoWizard,
    resetWizard,
    setCurrentStep,
  } = usePlaceStore();

  const isEditMode = !!id;

  // Load place data if editing
  useEffect(() => {
    if (isEditMode) {
      fetchPlaceById(parseInt(id))
        .then((place) => {
          loadPlaceIntoWizard(place);
        })
        .catch((error) => {
          toast({
            variant: "destructive",
            title: "Lỗi",
            description: error.message || "Không thể tải thông tin địa điểm",
          });
          navigate("/admin/places");
        });
    } else {
      resetWizard();
    }
     
  }, [id, isEditMode]);

  const steps = [
    {
      number: 1,
      title: "Thông tin cơ bản",
      description: "Tên & Danh mục",
      component: StepBasicInfo,
    },
    {
      number: 2,
      title: "Chi tiết",
      description: "Mô tả & Hình ảnh",
      component: StepDetails,
    },
    {
      number: 3,
      title: "Hoàn tất",
      description: "Xem trước & Lưu",
      component: StepPreview,
    },
  ];

  const currentStepData = steps.find((s) => s.number === currentStep);
  const StepComponent = currentStepData?.component;

  const handleBack = () => {
    navigate("/admin/places");
  };

  return (
    <div className="min-h-screen bg-slate-50/50 pb-20">
      {/* Top Header */}
      <div className="bg-white border-b border-slate-200 sticky top-0 z-40 bg-white/80 backdrop-blur-md">
        <div className="container mx-auto max-w-5xl px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <Button
              variant="ghost"
              size="icon"
              onClick={handleBack}
              className="rounded-full hover:bg-slate-100"
            >
              <ArrowLeft className="h-5 w-5 text-slate-600" />
            </Button>
            <div>
              <h1 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                {isEditMode ? "Chỉnh sửa địa điểm" : "Thêm địa điểm mới"}
                {!isEditMode && (
                  <Sparkles className="h-4 w-4 text-yellow-500 fill-yellow-500 animate-pulse" />
                )}
              </h1>
            </div>
          </div>

          <div className="flex items-center gap-2 text-sm font-medium text-slate-500">
            <span>Bước {currentStep}</span>
            <span className="text-slate-300">/</span>
            <span>{totalSteps}</span>
          </div>
        </div>

        {/* Progress Bar Line */}
        <div className="h-0.5 w-full bg-slate-100 overflow-hidden">
          <div
            className="h-full bg-primary transition-all duration-500 ease-out shadow-[0_0_10px_rgba(14,107,168,0.5)]"
            style={{ width: `${(currentStep / totalSteps) * 100}%` }}
          />
        </div>
      </div>

      <div className="container mx-auto px-4 py-8 max-w-5xl">
        {/* Stepper Visual */}
        <div className="mb-10 px-4">
          <div className="flex items-center justify-between relative">
            {/* Connecting Lines */}
            <div className="absolute left-0 top-1/2 -translate-y-1/2 w-full h-0.5 bg-slate-200 -z-10" />

            {steps.map((step) => {
              const isActive = step.number === currentStep;
              const isCompleted = step.number < currentStep;

              return (
                <div
                  key={step.number}
                  className="flex flex-col items-center bg-transparent gap-2 cursor-pointer group"
                  onClick={() =>
                    !loading &&
                    step.number < currentStep &&
                    setCurrentStep(step.number)
                  }
                >
                  <div
                    className={cn(
                      "w-10 h-10 rounded-full flex items-center justify-center border-4 transition-all duration-300 z-10",
                      isActive
                        ? "bg-primary border-white shadow-lg shadow-primary/20 scale-110"
                        : isCompleted
                          ? "bg-primary border-primary/10 text-white"
                          : "bg-white border-slate-200 text-slate-400",
                    )}
                  >
                    {isCompleted ? (
                      <Check className="h-5 w-5" />
                    ) : (
                      <span
                        className={cn(
                          "font-bold",
                          isActive ? "text-white" : "",
                        )}
                      >
                        {step.number}
                      </span>
                    )}
                  </div>
                  <div className="flex flex-col items-center">
                    <span
                      className={cn(
                        "text-sm font-bold transition-colors",
                        isActive
                          ? "text-slate-800"
                          : isCompleted
                            ? "text-primary"
                            : "text-slate-400",
                      )}
                    >
                      {step.title}
                    </span>
                    <span className="text-xs text-slate-400 hidden sm:block">
                      {step.description}
                    </span>
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Step Content */}
        <div className="">
          {StepComponent && <StepComponent isEditMode={isEditMode} />}
        </div>
      </div>
    </div>
  );
};

export default PlaceWizardPage;

import { useEffect, useState } from "react";
import { Button } from "@/components/ui";
import { useToast } from "@/hooks/use-toast";
import * as settingsService from "@/apis/settingsService";
import { DEFAULT_SETTINGS } from "./defaultSettings";
import GeneralSettingsCard from "./components/GeneralSettingsCard";
import MapSettingsCard from "./components/MapSettingsCard";
import EmailSettingsCard from "./components/EmailSettingsCard";
import SecuritySettingsCard from "./components/SecuritySettingsCard";
import FeatureModulesCard from "./components/FeatureModulesCard";
import IntegrationsCard from "./components/IntegrationsCard";
import LogsMonitoringCard from "./components/LogsMonitoringCard";
import OperationsCard from "./components/OperationsCard";
import SeoDisplayCard from "./components/SeoDisplayCard";

/** Map từ API có thể là number — input controlled cần string */
const normalizeMapDefault = (input) => {
  if (!input || typeof input !== "object") return input;
  return {
    ...input,
    latitude:
      input.latitude != null && input.latitude !== ""
        ? String(input.latitude)
        : "",
    longitude:
      input.longitude != null && input.longitude !== ""
        ? String(input.longitude)
        : "",
    zoom:
      input.zoom != null && input.zoom !== "" ? String(input.zoom) : "",
  };
};

const mergeRemoteSettings = (prev, data) => {
  if (!data || typeof data !== "object") return prev;
  return {
    ...prev,
    ...data,
    general: { ...prev.general, ...(data.general || {}) },
    mapDefault: normalizeMapDefault({
      ...prev.mapDefault,
      ...(data.mapDefault || {}),
    }),
    email: { ...prev.email, ...(data.email || {}) },
    security: { ...prev.security, ...(data.security || {}) },
    modules: { ...prev.modules, ...(data.modules || {}) },
    integrations: { ...prev.integrations, ...(data.integrations || {}) },
    logs: { ...prev.logs, ...(data.logs || {}) },
    operations: { ...prev.operations, ...(data.operations || {}) },
    seo: { ...prev.seo, ...(data.seo || {}) },
  };
};

const safeNum = (v, fallback = 0) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : fallback;
};

const SettingsPageContent = () => {
  const { toast } = useToast();
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [settings, setSettings] = useState(DEFAULT_SETTINGS);

  useEffect(() => {
    let disposed = false;

    const loadSettings = async () => {
      setLoading(true);
      try {
        const response = await settingsService.getSettings();
        const data = response?.data || {};
        if (disposed) return;

        setSettings((prev) => mergeRemoteSettings(prev, data));
      } catch (error) {
        if (!disposed) {
          toast({
            variant: "destructive",
            title: "LỖI TẢI CẤU HÌNH",
            description: error.message || "Không thể tải cài đặt hệ thống.",
          });
        }
      } finally {
        if (!disposed) setLoading(false);
      }
    };

    loadSettings();
    return () => {
      disposed = true;
    };
  }, []);

  const updateSectionField = (section, key, value) => {
    setSettings((prev) => ({
      ...prev,
      [section]: {
        ...prev[section],
        [key]: value,
      },
    }));
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const payload = {
        ...settings,
        mapDefault: {
          latitude: safeNum(settings.mapDefault?.latitude, 10.0452),
          longitude: safeNum(settings.mapDefault?.longitude, 105.7469),
          zoom: safeNum(settings.mapDefault?.zoom, 13),
        },
        security: {
          ...settings.security,
          sessionTimeoutMinutes: safeNum(
            settings.security?.sessionTimeoutMinutes,
            30,
          ),
        },
        modules: {
          ...settings.modules,
          maxUploadSizeMb: safeNum(settings.modules?.maxUploadSizeMb, 20),
        },
        logs: {
          ...settings.logs,
          retentionDays: safeNum(settings.logs?.retentionDays, 30),
        },
      };

      const res = await settingsService.updateSettings(payload);
      const saved = res?.data;
      if (saved) {
        setSettings((prev) => mergeRemoteSettings(prev, saved));
      }

      toast({
        title: "ĐÃ LƯU CẤU HÌNH",
        description: "Cài đặt hệ thống đã được cập nhật.",
        className: "bg-black text-white border border-primary font-mono",
      });
    } catch (error) {
      toast({
        variant: "destructive",
        title: "LỖI LƯU CẤU HÌNH",
        description:
          error.message ||
          error?.data?.message ||
          "Không thể lưu cài đặt. Kiểm tra quyền đăng nhập (Super Admin / Admin).",
      });
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="min-h-screen p-8 bg-[#F4F4F4] relative font-sans">
      <div className="absolute inset-0 bg-grid-pattern bg-grid-20 opacity-30 pointer-events-none" />

      <div className="relative z-10 space-y-6 max-w-[1550px] mx-auto">
        <div className="flex items-end justify-between border-b-2 border-black pb-6">
          <div className="flex items-center gap-6">
            <div className="accent-bar h-16" />
            <div>
              <h1 className="tim-title">CÀI ĐẶT HỆ THỐNG</h1>
              <div className="flex items-center gap-4 mt-2">
                <span className="tim-system bg-black text-white px-2 py-1">
                  HỆ THỐNG // CẤU HÌNH
                </span>
                <p className="tim-meta">
                  Chung, bản đồ, email, bảo mật, module, tích hợp, nhật ký, vận
                  hành, SEO
                </p>
              </div>
            </div>
          </div>

          <Button
            type="button"
            onClick={handleSave}
            disabled={loading || saving}
            className="h-11 rounded-none border border-black bg-black text-white hover:bg-[#F3E600] hover:text-black font-bold uppercase px-6"
          >
            {saving ? "ĐANG LƯU..." : "LƯU CÀI ĐẶT"}
          </Button>
        </div>

        <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
          <GeneralSettingsCard
            value={settings.general}
            onChange={(key, value) => updateSectionField("general", key, value)}
          />

          <MapSettingsCard
            value={settings.mapDefault}
            onChange={(key, value) =>
              updateSectionField("mapDefault", key, value)
            }
          />

          <EmailSettingsCard
            value={settings.email}
            onChange={(key, value) => updateSectionField("email", key, value)}
          />

          <SecuritySettingsCard
            value={settings.security}
            onChange={(key, value) =>
              updateSectionField("security", key, value)
            }
          />

          <FeatureModulesCard
            value={settings.modules}
            onChange={(key, value) => updateSectionField("modules", key, value)}
          />

          <IntegrationsCard
            value={settings.integrations}
            onChange={(key, value) =>
              updateSectionField("integrations", key, value)
            }
          />

          <LogsMonitoringCard
            value={settings.logs}
            onChange={(key, value) => updateSectionField("logs", key, value)}
          />

          <OperationsCard
            value={settings.operations}
            onChange={(key, value) =>
              updateSectionField("operations", key, value)
            }
          />

          <SeoDisplayCard
            value={settings.seo}
            onChange={(key, value) => updateSectionField("seo", key, value)}
          />
        </div>
      </div>
    </div>
  );
};

export default SettingsPageContent;

import { useState, useEffect, useCallback } from "react";
import { useSearchParams, useNavigate, Link } from "react-router-dom";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/Card";
import { Button } from "@/components/ui/Button";
import { CheckCircle2, XCircle, Loader2, Mail } from "lucide-react";
import { authService } from "@/apis";
import toast from "react-hot-toast";

const VerifyEmailPublicPage = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const token = searchParams.get("token");

  const [status, setStatus] = useState("verifying"); // verifying | success | error
  const [message, setMessage] = useState("");

  const verifyEmail = useCallback(async () => {
    if (!token) {
      setStatus("error");
      setMessage("Token không hợp lệ. Vui lòng kiểm tra lại link trong email.");
      return;
    }

    try {
      setStatus("verifying");
      const response = await authService.verifyEmail({ token });
      setStatus("success");
      setMessage(response.message || "Xác thực email thành công!");
      toast.success("✅ Xác thực email thành công!");

      // Auto redirect sau 3 giây
      setTimeout(() => {
        navigate("/login", {
          state: { message: "Email đã được xác thực. Vui lòng đăng nhập." },
        });
      }, 3000);
    } catch (error) {
      setStatus("error");
      const errorMsg =
        error.response?.data?.message || error.message || "Xác thực thất bại";
      setMessage(errorMsg);
      toast.error(`❌ ${errorMsg}`);
    }
  }, [navigate, token]);

  useEffect(() => {
    verifyEmail();
  }, [verifyEmail]);

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 via-white to-purple-50 p-4">
      <Card className="w-full max-w-md shadow-xl">
        <CardHeader className="text-center">
          <div className="flex justify-center mb-4">
            {status === "verifying" && (
              <div className="w-20 h-20 rounded-full bg-blue-100 flex items-center justify-center">
                <Loader2 className="w-10 h-10 text-blue-600 animate-spin" />
              </div>
            )}
            {status === "success" && (
              <div className="w-20 h-20 rounded-full bg-green-100 flex items-center justify-center">
                <CheckCircle2 className="w-10 h-10 text-green-600" />
              </div>
            )}
            {status === "error" && (
              <div className="w-20 h-20 rounded-full bg-red-100 flex items-center justify-center">
                <XCircle className="w-10 h-10 text-red-600" />
              </div>
            )}
          </div>
          <CardTitle className="text-2xl font-bold">
            {status === "verifying" && "Đang xác thực email..."}
            {status === "success" && "Xác thực thành công!"}
            {status === "error" && "Xác thực thất bại"}
          </CardTitle>
        </CardHeader>

        <CardContent className="space-y-6">
          {/* Message */}
          <div className="text-center">
            <p className="text-gray-600">{message}</p>
          </div>

          {/* Actions */}
          <div className="space-y-3">
            {status === "success" && (
              <>
                <Button
                  onClick={() => navigate("/login")}
                  className="w-full bg-green-600 hover:bg-green-700"
                >
                  Đi đến Đăng nhập
                </Button>
                <p className="text-sm text-gray-500 text-center">
                  Tự động chuyển hướng sau 3 giây...
                </p>
              </>
            )}

            {status === "error" && (
              <>
                <Button
                  onClick={verifyEmail}
                  className="w-full bg-blue-600 hover:bg-blue-700"
                >
                  Thử lại
                </Button>
                <Button
                  onClick={() => navigate("/resend-verification")}
                  variant="outline"
                  className="w-full"
                >
                  <Mail className="mr-2 h-4 w-4" />
                  Gửi lại email xác thực
                </Button>
                <div className="border-t pt-4 mt-4">
                  <p className="text-sm text-gray-600 text-center mb-3">
                    Các lỗi thường gặp:
                  </p>
                  <ul className="text-xs text-gray-500 space-y-2">
                    <li>
                      • <strong>Token đã hết hạn:</strong> Token có hiệu lực 24
                      giờ. Vui lòng gửi lại email xác thực.
                    </li>
                    <li>
                      • <strong>Token không hợp lệ:</strong> Link có thể bị sai.
                      Kiểm tra lại email hoặc gửi lại.
                    </li>
                    <li>
                      • <strong>Email đã xác thực:</strong> Tài khoản của bạn đã
                      được xác thực. Vui lòng đăng nhập.
                    </li>
                  </ul>
                </div>
              </>
            )}

            {status === "verifying" && (
              <div className="text-center">
                <p className="text-sm text-gray-500">
                  Vui lòng đợi trong giây lát...
                </p>
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="border-t pt-4 text-center">
            <p className="text-sm text-gray-600">
              Chưa có tài khoản?{" "}
              <Link
                to="/register"
                className="text-blue-600 hover:underline font-medium"
              >
                Đăng ký ngay
              </Link>
            </p>
            <p className="text-sm text-gray-600 mt-2">
              <Link to="/login" className="text-blue-600 hover:underline">
                Quay lại Đăng nhập
              </Link>
            </p>
          </div>
        </CardContent>
      </Card>
    </div>
  );
};

export default VerifyEmailPublicPage;

