// ─── Main Page ────────────────────────────────────────────────────────────────

const BookingListPage = () => {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState(null);
  const [places, setPlaces] = useState([]);
  const [search, setSearch] = useState("");
  const [status, setStatus] = useState("all");
  const [selectedPlaceId, setSelectedPlaceId] = useState("all");
  const [fromDate, setFromDate] = useState("");
  const [toDate, setToDate] = useState("");
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [total, setTotal] = useState(0);
  const [selected, setSelected] = useState([]);
  const [cancelModal, setCancelModal] = useState(null);
  const [bulkLoading, setBulkLoading] = useState(false);
  const [isPendingTransition, startTransition] = useTransition();

  const loadBookings = useCallback(async () => {
    setLoading(true);
    try {
      const response = await bookingApi.getAll({
        search,
        status,
        page,
        limit: PAGE_SIZE,
        ...(selectedPlaceId !== "all" && { placeId: selectedPlaceId }),
        ...(fromDate && { fromDate }),
        ...(toDate && { toDate }),
      });
      setBookings(response.data || []);
      setTotalPages(response.pagination?.totalPages || 1);
      setTotal(response.pagination?.total || 0);
    } catch {
      toast.error("Không thể tải danh sách đặt chỗ");
    } finally {
      setLoading(false);
    }
  }, [search, status, page, fromDate, toDate, selectedPlaceId]);

  const loadStats = useCallback(async () => {
    try {
      const response = await bookingApi.getStats();
      setStats(response.data);
    } catch {
      // Keep UI usable even if stats endpoint is temporarily unavailable.
    }
  }, []);

  useEffect(() => {
    loadBookings();
  }, [loadBookings]);
  useEffect(() => {
    loadStats();
  }, [loadStats]);
  useEffect(() => {
    getMyPlaces()
      .then((res) => setPlaces(res.data || []))
      .catch(() => {});
  }, []);
  useEffect(() => {
    setPage(1);
  }, [search, status, fromDate, toDate, selectedPlaceId]);

  const refresh = () => {
    loadBookings();
    loadStats();
  };

  const handleConfirm = async (id) => {
    try {
      await bookingApi.confirm(id);
      toast.success("Xác nhận thành công");
      refresh();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể xác nhận");
    }
  };

  const handleCancelConfirmed = async (reason) => {
    try {
      await bookingApi.cancel(cancelModal, reason);
      toast.success("Hủy đặt chỗ thành công");
      setCancelModal(null);
      refresh();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể hủy");
    }
  };

  const handleComplete = async (id) => {
    try {
      await bookingApi.complete(id);
      toast.success("Hoàn thành đặt chỗ");
      refresh();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể hoàn thành");
    }
  };

  const handleNoShow = async (id) => {
    try {
      await bookingApi.markNoShow(id);
      toast.success("Đánh dấu không đến");
      refresh();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể đánh dấu");
    }
  };

  const handleBulkConfirm = async () => {
    if (pendingSelected.length === 0) return;
    try {
      setBulkLoading(true);
      await bookingApi.bulkConfirm(pendingSelected);
      toast.success(`Đã xác nhận ${pendingSelected.length} đặt chỗ`);
      setSelected([]);
      refresh();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể xác nhận hàng loạt");
    } finally {
      setBulkLoading(false);
    }
  };

  const handleBulkCancel = async (reason) => {
    if (pendingSelected.length === 0) return;
    if (!reason || reason.trim().length < 5) {
      toast.error("Lý do hủy cần ít nhất 5 ký tự");
      return;
    }

    try {
      setBulkLoading(true);
      const response = await bookingApi.bulkCancel(pendingSelected, reason);
      const result = response?.data || {};
      const successCount = Array.isArray(result.success)
        ? result.success.length
        : pendingSelected.length;
      const failedCount = Array.isArray(result.failed)
        ? result.failed.length
        : 0;

      if (failedCount > 0) {
        toast.success(
          `Đã hủy ${successCount} đặt chỗ, thất bại ${failedCount}`,
        );
      } else {
        toast.success(`Đã hủy ${successCount} đặt chỗ`);
      }

      setSelected([]);
      refresh();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể hủy hàng loạt");
    } finally {
      setBulkLoading(false);
    }
  };

  const toggleSelect = (id) =>
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((s) => s !== id) : [...prev, id],
    );

  const pendingSelected = selected.filter((id) => {
    const bk = bookings.find((b) => b.id === id);
    return bk?.status === BOOKING_STATUS.PENDING;
  });

  const handleStatusChange = (nextStatus) => {
    startTransition(() => {
      setStatus(nextStatus);
    });
  };

  // Stat cards dữ liệu
  const statCards = [
    {
      key: BOOKING_STATUS.PENDING,
      label: "Chờ xác nhận",
      icon: Clock,
      iconColor: "amber",
    },
    {
      key: BOOKING_STATUS.CONFIRMED,
      label: "Đã xác nhận",
      icon: CheckCheck,
      iconColor: "blue",
    },
    {
      key: BOOKING_STATUS.COMPLETED,
      label: "Hoàn thành",
      icon: CheckCircle,
      iconColor: "emerald",
    },
    {
      key: BOOKING_STATUS.CANCELLED,
      label: "Đã hủy",
      icon: XCircle,
      iconColor: "rose",
    },
    {
      key: BOOKING_STATUS.NO_SHOW,
      label: "Không đến",
      icon: UserX,
      iconColor: "primary",
    },
  ];

  return (
    <div className="space-y-6 p-6 lg:p-8 min-h-screen">
      {/* Header */}
      <PageHeader
        title="Quản lý đặt chỗ"
        subtitle="Theo dõi, xác nhận và quản lý các đặt chỗ của khách hàng"
        badge={total > 0 ? total : undefined}
        action={
          pendingSelected.length > 0 && (
            <Button onClick={handleBulkConfirm} className="gap-2">
              <Check className="h-4 w-4" />
              Xác nhận {pendingSelected.length} đặt chỗ
            </Button>
          )
        }
      />

      {/* Status Stat Cards */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
        {statCards.map(({ key, label }) =>
          loading ? (
            <StatCardSkeleton key={key} />
          ) : (
            <button
              key={key}
              type="button"
              onClick={() => handleStatusChange(status === key ? "all" : key)}
              className={cn(
                "rounded-xl border border-border/60 shadow-sm bg-card p-4 text-left transition-all hover:shadow-md hover:-translate-y-0.5",
                status === key && "ring-2 ring-primary border-primary/50",
              )}
            >
              <p className="text-2xl font-bold text-foreground">
                {stats?.byStatus?.[key] || 0}
              </p>
              <p className="text-xs text-muted-foreground mt-1">{label}</p>
            </button>
          ),
        )}
      </div>

      {/* Toolbar + List trong Tabs */}
      <SectionCard
        title="Danh sách đặt chỗ"
        titleIcon={CalendarCheck}
        bodyClassName="p-0"
        action={
          <div className="flex flex-wrap items-center gap-2">
            {/* Date range */}
            <div className="flex items-center gap-1.5">
              <CalendarRange className="h-3.5 w-3.5 text-muted-foreground" />
              <input
                type="date"
                value={fromDate}
                onChange={(e) => setFromDate(e.target.value)}
                className="h-8 border border-border rounded-md px-2 text-xs bg-background focus:outline-none focus:ring-1 focus:ring-primary w-32"
              />
              <span className="text-muted-foreground text-xs">→</span>
              <input
                type="date"
                value={toDate}
                min={fromDate}
                onChange={(e) => setToDate(e.target.value)}
                className="h-8 border border-border rounded-md px-2 text-xs bg-background focus:outline-none focus:ring-1 focus:ring-primary w-32"
              />
              {(fromDate || toDate) && (
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-8 w-8 p-0"
                  onClick={() => {
                    setFromDate("");
                    setToDate("");
                  }}
                >
                  <X className="h-3.5 w-3.5" />
                </Button>
              )}
            </div>

            {/* Place filter */}
            <Select value={selectedPlaceId} onValueChange={setSelectedPlaceId}>
              <SelectTrigger className="h-8 text-xs w-40">
                <SelectValue placeholder="Tất cả địa điểm" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Tất cả địa điểm</SelectItem>
                {places.map((place) => (
                  <SelectItem key={place.id} value={String(place.id)}>
                    {place.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            {/* Search */}
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground pointer-events-none" />
              <Input
                placeholder="Tìm mã / tên khách..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-8 h-8 text-xs w-48"
              />
            </div>
          </div>
        }
      >
        <Tabs value={status} onValueChange={handleStatusChange}>
          <div className="px-5 border-b border-border/60">
            <TabsList className="h-10 bg-transparent gap-1 p-0">
              {STATUS_TABS.map((tab) => (
                <TabsTrigger
                  key={tab.value}
                  value={tab.value}
                  className={DESIGN.tabUnderlineTrigger}
                >
                  {tab.label}
                  {stats?.byStatus?.[tab.value] !== undefined &&
                    tab.value !== "all" && (
                      <span className="ml-1.5 text-muted-foreground">
                        ({stats.byStatus[tab.value]})
                      </span>
                    )}
                </TabsTrigger>
              ))}
            </TabsList>
            {isPendingTransition && (
              <p className="py-1 text-[11px] text-muted-foreground">
                Đang cập nhật danh sách...
              </p>
            )}
          </div>

          {STATUS_TABS.map((tab) => (
            <TabsContent key={tab.value} value={tab.value} className="mt-0">
              <div className="px-5 py-2">
                {loading ? (
                  <div className="space-y-0">
                    {Array.from({ length: 6 }).map((_, i) => (
                      <div
                        key={i}
                        className="flex items-center gap-4 py-4 border-b border-border/50 last:border-0"
                      >
                        <div className="flex-1 space-y-1.5">
                          <Skeleton className="h-4 w-36" />
                          <Skeleton className="h-3.5 w-48" />
                          <Skeleton className="h-3 w-32" />
                        </div>
                        <Skeleton className="h-8 w-20 rounded-md" />
                      </div>
                    ))}
                  </div>
                ) : bookings.length === 0 ? (
                  <EmptyState
                    icon={CalendarCheck}
                    message="Không có đặt chỗ nào."
                  />
                ) : (
                  <div>
                    {bookings.map((bk) => (
                      <BookingItem
                        key={bk.id}
                        bk={bk}
                        selected={selected.includes(bk.id)}
                        onSelect={toggleSelect}
                        onConfirm={handleConfirm}
                        onCancel={(id) => setCancelModal(id)}
                        onComplete={handleComplete}
                        onNoShow={handleNoShow}
                        onView={(id) =>
                          navigate(BUSINESS_ROUTES.BOOKING_DETAIL(id))
                        }
                      />
                    ))}
                    {totalPages > 1 && (
                      <div className="border-t border-border/60 mt-2 pt-2">
                        <PageNav
                          page={page}
                          totalPages={totalPages}
                          total={total}
                          onPageChange={setPage}
                        />
                      </div>
                    )}
                  </div>
                )}
              </div>
            </TabsContent>
          ))}
        </Tabs>
      </SectionCard>

      <CancelModal
        open={!!cancelModal}
        onConfirm={handleCancelConfirmed}
        onCancel={() => setCancelModal(null)}
      />

      <BulkActionBar
        selectedCount={pendingSelected.length}
        onBulkConfirm={handleBulkConfirm}
        onBulkCancel={handleBulkCancel}
        onClearSelection={() => setSelected([])}
        loading={bulkLoading}
      />
    </div>
  );
};

