                  <div>
                    <p className="text-xs font-medium text-muted-foreground uppercase tracking-wide">
                      Tổng doanh thu
                    </p>
                    <p className="text-lg font-bold text-foreground leading-tight">
                      {formatVND(overview?.totalRevenue ?? stats?.totalRevenue)}
