const VoucherListPage = () => {
  const [vouchers, setVouchers] = useState([]);
  const [places, setPlaces] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [selectedPlaceId, setSelectedPlaceId] = useState("all");
  const [showForm, setShowForm] = useState(false);
  const [editVoucher, setEditVoucher] = useState(null);
  const [selected, setSelected] = useState([]);
  const [deleteTarget, setDeleteTarget] = useState(null);

  const loadVouchers = useCallback(async () => {
    setLoading(true);
    try {
      const response = await voucherApi.getAll({ search, page: 1, limit: 50 });
      setVouchers(response.data || []);
    } catch {
      toast.error("Không thể tải danh sách voucher");
    } finally {
      setLoading(false);
    }
  }, [search]);

  useEffect(() => {
    loadVouchers();
  }, [loadVouchers]);
  useEffect(() => {
    getMyPlaces()
      .then((res) => setPlaces(res.data || []))
      .catch(() => {});
  }, []);

  const filteredVouchers = useMemo(() => {
    if (selectedPlaceId === "all") return vouchers;
    return vouchers.filter((v) => {
      const placeIds = v?.applicableServices?.placeIds || [];
      if (!Array.isArray(placeIds) || placeIds.length === 0) return true;
      return placeIds.includes(Number(selectedPlaceId));
    });
  }, [vouchers, selectedPlaceId]);

  const activeCount = filteredVouchers.filter((v) => v.isActive).length;
  const expiredCount = filteredVouchers.filter(
    (v) => v.endDate && new Date(v.endDate) < new Date(),
  ).length;

  const handleCreate = async (data) => {
    await voucherApi.create(data);
    toast.success("Tạo voucher thành công");
    loadVouchers();
  };

  const handleUpdate = async (data) => {
    await voucherApi.update(editVoucher.id, data);
    toast.success("Cập nhật voucher thành công");
    setEditVoucher(null);
    loadVouchers();
  };

  const handleDelete = async (id) => {
    try {
      await voucherApi.remove(id);
      toast.success("Xóa voucher thành công");
      loadVouchers();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể xóa");
    }
  };

  const handleBulkDeactivate = async () => {
    if (selected.length === 0) return;
    try {
      await voucherApi.bulkDeactivate(selected);
      toast.success(`Đã tắt ${selected.length} voucher`);
      setSelected([]);
      loadVouchers();
    } catch (error) {
      toastApiErrorIfNeeded(error, "Không thể tắt voucher");
    }
  };

  const toggleSelect = (id) =>
    setSelected((prev) =>
      prev.includes(id) ? prev.filter((s) => s !== id) : [...prev, id],
    );

  const openEdit = (v) => {
    setEditVoucher(v);
    setShowForm(true);
  };
  const closeForm = () => {
    setShowForm(false);
    setEditVoucher(null);
  };

  return (
    <div className="space-y-6 p-6 lg:p-8 min-h-screen">
      {/* Header */}
      <PageHeader
        title="Quản lý voucher"
        subtitle="Tạo và quản lý các mã giảm giá cho dịch vụ của bạn"
        badge={
          filteredVouchers.length > 0 ? filteredVouchers.length : undefined
        }
        action={
          <div className="flex gap-2">
            {selected.length > 0 && (
              <Button
                variant="outline"
                onClick={handleBulkDeactivate}
                className="gap-2"
              >
                <ToggleLeft className="h-4 w-4" />
                Tắt {selected.length} voucher
              </Button>
            )}
            <Button onClick={() => setShowForm(true)} className="gap-2">
              <Plus className="h-4 w-4" />
              Tạo voucher
            </Button>
          </div>
        }
      />

      {/* Quick Stats */}
      {!loading && (
        <div className="grid grid-cols-3 gap-3">
          {[
            {
              label: "Tổng voucher",
              value: filteredVouchers.length,
              color: "text-foreground",
            },
            {
              label: "Đang hoạt động",
              value: activeCount,
              color: "text-emerald-600",
            },
            {
              label: "Hết hạn",
              value: expiredCount,
              color: "text-destructive",
            },
          ].map(({ label, value, color }) => (
            <div
              key={label}
              className={`rounded-xl border border-border/60 shadow-sm bg-card p-4 text-center`}
            >
              <p className={`text-2xl font-bold ${color}`}>{value}</p>
              <p className="text-xs text-muted-foreground mt-0.5">{label}</p>
            </div>
          ))}
        </div>
      )}

      {/* List */}
      <SectionCard
        title="Danh sách voucher"
        titleIcon={Tag}
        action={
          <div className="flex gap-2">
            <Select value={selectedPlaceId} onValueChange={setSelectedPlaceId}>
              <SelectTrigger className="h-8 text-xs w-40">
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">Tất cả địa điểm</SelectItem>
                {places.map((p) => (
                  <SelectItem key={p.id} value={String(p.id)}>
                    {p.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            <div className="relative">
              <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5 text-muted-foreground pointer-events-none" />
              <Input
                placeholder="Tìm mã / tên..."
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="pl-8 h-8 text-xs w-40"
              />
            </div>
          </div>
        }
      >
        {loading ? (
          <div className="space-y-3">
            {Array.from({ length: 3 }).map((_, i) => (
              <Skeleton key={i} className="h-28 rounded-xl" />
            ))}
          </div>
        ) : filteredVouchers.length === 0 ? (
          <EmptyState
            icon={Tag}
            message="Chưa có voucher nào. Nhấn 'Tạo voucher' để bắt đầu."
            action={
              <Button
                size="sm"
                onClick={() => setShowForm(true)}
                className="gap-1.5"
              >
                <Plus className="h-3.5 w-3.5" /> Tạo voucher
              </Button>
            }
          />
        ) : (
          <div className="space-y-3">
            {filteredVouchers.map((v) => (
              <VoucherCard
                key={v.id}
                voucher={v}
                places={places}
                selected={selected.includes(v.id)}
                onSelect={toggleSelect}
                onEdit={openEdit}
                onDelete={(id) =>
                  setDeleteTarget(
                    filteredVouchers.find((item) => item.id === id) || null,
                  )
                }
              />
            ))}
          </div>
        )}
      </SectionCard>

      <VoucherFormModal
        open={showForm}
        voucher={editVoucher}
        places={places}
        onSave={editVoucher ? handleUpdate : handleCreate}
        onClose={closeForm}
      />

      <ConfirmDeleteVoucherModal
        open={!!deleteTarget}
        code={deleteTarget?.code}
        onConfirm={async () => {
          if (!deleteTarget) return;
          await handleDelete(deleteTarget.id);
          setDeleteTarget(null);
        }}
        onCancel={() => setDeleteTarget(null)}
      />
    </div>
  );
};

export default VoucherListPage;

import { create } from "zustand";
import { devtools } from "zustand/middleware";
import * as placeService from "@/apis/placeService";
import { PAGINATION, API_BASE_URL } from "@/constants/constants";

/**
 * PLACE STORE
 * State management cho places
 */

const usePlaceStore = create(
  devtools(
    (set, get) => ({
      // State
      places: [],
      selectedPlace: null,
      featuredPlaces: [],
      nearbyPlaces: [],
      loading: false,
      error: null,
      pagination: {
        page: PAGINATION.DEFAULT_PAGE,
        limit: PAGINATION.DEFAULT_LIMIT,
        total: 0,
        totalPages: 0,
      },

      // Wizard state for creating/editing place
      wizardData: {
        // Step 1: Basic Info
        name: "",
        slug: "",
        categoryId: null,
        districtId: null,
        wardId: null,
        address: "",
        shortDescription: "",

        // Step 2: Details
        description: "",
        latitude: null,
        longitude: null,
        phone: "",
        email: "",
        website: "",
        facebook: "",
        images: [],

        // Step 3: Tags & Pricing
        tagIds: [],
        priceRange: null,
        priceFrom: null,
        priceTo: null,
        openingHours: [],
        amenities: [],

        // Meta
        status: "draft",
      },

      currentStep: 1,
      totalSteps: 3,

      // Actions
      fetchPlaces: async (params = {}) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.getAllPlaces(params);
          set({
            places: response.data || [],
            pagination: response.pagination || get().pagination,
            loading: false,
          });
          return response.data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      fetchPlaceById: async (id, incrementView = false) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.getPlaceById(id, incrementView);
          const data = response.data || response;
          set({ selectedPlace: data, loading: false });
          return data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      fetchPlaceBySlug: async (slug, incrementView = false) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.getPlaceBySlug(
            slug,
            incrementView,
          );
          const data = response.data || response;
          set({ selectedPlace: data, loading: false });
          return data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      checkSlugExists: async (slug, excludeId = null) => {
        try {
          const response = await placeService.checkSlugExists(slug, excludeId);
          return response.data?.exists || false;
        } catch {
          return false;
        }
      },

      fetchFeaturedPlaces: async (limit = 10, categoryId = null) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.getFeaturedPlaces(
            limit,
            categoryId,
          );
          const data = response.data || response;
          set({ featuredPlaces: data, loading: false });
          return data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      fetchNearbyPlaces: async (
        latitude,
        longitude,
        radius = 5,
        limit = 10,
      ) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.getNearbyPlaces(
            latitude,
            longitude,
            radius,
            limit,
          );
          const data = response.data || response;
          set({ nearbyPlaces: data, loading: false });
          return data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      lookupLocation: async (latitude, longitude) => {
        try {
          const response = await fetch(`${API_BASE_URL}/districts/lookup`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ latitude, longitude }),
          });
          const data = await response.json();

          if (data.success && data.data) {
            set((state) => ({
              wizardData: {
                ...state.wizardData,
                districtId: data.data.id,
                wardId: null,
              },
            }));
            return data.data;
          }
          return null;
        } catch (error) {
          console.error("Lookup failed", error);
          return null;
        }
      },

      createPlace: async (data) => {
        set({ loading: true, error: null });
        try {
          // Sanitize numeric fields to ensure they are numbers (not strings)
          const payload = {
            ...data,
            categoryId: data.categoryId ? parseInt(data.categoryId) : undefined,
            districtId: data.districtId ? parseInt(data.districtId) : undefined,
            wardId: data.wardId ? parseInt(data.wardId) : null,
            latitude: data.latitude ? parseFloat(data.latitude) : undefined,
            longitude: data.longitude ? parseFloat(data.longitude) : undefined,
            priceFrom: data.priceFrom ? parseInt(data.priceFrom) : null,
            priceTo: data.priceTo ? parseInt(data.priceTo) : null,
            // Ensure businessId is number if exists
            businessId: data.businessId ? parseInt(data.businessId) : undefined,
            // Sanitize optional string fields - empty strings should be null/undefined
            website: data.website?.trim() || undefined,
            email: data.email?.trim() || undefined,
            facebook: data.facebook?.trim() || undefined,
            phone: data.phone?.trim() || undefined,
            // Sanitize priceRange - null/empty should be undefined to satisfy optional validation
            priceRange: data.priceRange || undefined,
            // Remove status, handle in backend
          };

          const response = await placeService.createPlace(payload);
          const newPlace = response.data || response;

          // Refresh places list
          await get().fetchPlaces();

          set({ loading: false });
          return newPlace;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      updatePlace: async (id, data) => {
        set({ loading: true, error: null });
        try {
          // Sanitize numeric fields
          const payload = {
            ...data,
          };

          if (data.categoryId !== undefined)
            payload.categoryId = parseInt(data.categoryId);
          // ... rest same logic

          if (data.districtId !== undefined)
            payload.districtId = parseInt(data.districtId);
          if (data.wardId !== undefined)
            payload.wardId = data.wardId ? parseInt(data.wardId) : null;
          if (data.latitude !== undefined)
            payload.latitude = parseFloat(data.latitude);
          if (data.longitude !== undefined)
            payload.longitude = parseFloat(data.longitude);
          if (data.priceFrom !== undefined)
            payload.priceFrom = data.priceFrom
              ? parseInt(data.priceFrom)
              : null;
          if (data.priceTo !== undefined)
            payload.priceTo = data.priceTo ? parseInt(data.priceTo) : null;

          // Sanitize optional string fields
          if (data.website !== undefined)
            payload.website = data.website?.trim() || undefined;
          if (data.email !== undefined)
            payload.email = data.email?.trim() || undefined;
          if (data.facebook !== undefined)
            payload.facebook = data.facebook?.trim() || undefined;
          if (data.phone !== undefined)
            payload.phone = data.phone?.trim() || undefined;
          if (data.priceRange !== undefined)
            payload.priceRange = data.priceRange || undefined;

          // Status can be updated via specific endpoint or here if allowed, but for create we remove it.
          // Keeping it here for Update if admin wants to changing it? User said "Remove status from Form create".
          // So updatePlace logic can remain for now.

          const response = await placeService.updatePlace(id, payload);
          const updatedPlace = response.data || response;

          // Refresh places list
          await get().fetchPlaces();

          set({ loading: false });
          return updatedPlace;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      deletePlace: async (id) => {
        set({ loading: true, error: null });
        try {
          await placeService.deletePlace(id);

          // Refresh places list
          await get().fetchPlaces();

          set({ loading: false });
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      updatePlaceStatus: async (id, status) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.updatePlaceStatus(id, status);
          await get().fetchPlaces();
          set({ loading: false });
          return response.data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      approvePlace: async (id) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.approvePlace(id);
          await get().fetchPlaces();
          set({ loading: false });
          return response.data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      rejectPlace: async (id, reason) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.rejectPlace(id, reason);
          await get().fetchPlaces();
          set({ loading: false });
          return response.data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      toggleFeature: async (id) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.toggleFeature(id);
          await get().fetchPlaces();
          set({ loading: false });
          return response.data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      toggleVerify: async (id) => {
        set({ loading: true, error: null });
        try {
          const response = await placeService.toggleVerify(id);
          await get().fetchPlaces();
          set({ loading: false });
          return response.data;
        } catch (error) {
          set({ error: error.message, loading: false });
          throw error;
        }
      },

      // Wizard actions
      updateWizardData: (data) => {
        set((state) => ({
          wizardData: { ...state.wizardData, ...data },
        }));
      },

      setCurrentStep: (step) => {
        set({ currentStep: step });
      },

      nextStep: () => {
        set((state) => ({
          currentStep: Math.min(state.currentStep + 1, state.totalSteps),
        }));
      },

      prevStep: () => {
        set((state) => ({
          currentStep: Math.max(state.currentStep - 1, 1),
        }));
      },

      resetWizard: () => {
        set({
          wizardData: {
            name: "",
            slug: "",
            categoryId: null,
            districtId: null,
            wardId: null,
            address: "",
            shortDescription: "",
            description: "",
            latitude: null,
            longitude: null,
            phone: "",
            email: "",
            website: "",
            facebook: "",
            images: [],
            tagIds: [],
            priceRange: null,
            priceFrom: null,
            priceTo: null,
            openingHours: [],
            amenities: [],
            // No status default here needed or default to null, backend handles it.
          },
          currentStep: 1,
        });
      },

      loadPlaceIntoWizard: (place) => {
        set({
          wizardData: {
            id: place.id, // Important: ID for updates
            name: place.name || "",
            slug: place.slug || "",
            categoryId: place.categoryId || null,
            districtId: place.districtId || null,
            wardId: place.wardId || null,
            address: place.address || "",
            shortDescription: place.shortDescription || "",
            description: place.description || "",
            latitude: place.latitude || null,
            longitude: place.longitude || null,
            phone: place.phone || "",
            email: place.email || "",
            website: place.website || "",
            facebook: place.facebook || "",
            images: place.images || [],
            tagIds: place.tags
              ? place.tags.map((t) => t.id)
              : place.tagLinks
                ? place.tagLinks
                    .map((l) => l.tagId || l.tag?.id)
                    .filter(Boolean)
                : [],
            priceRange: place.priceRange || null,
            priceFrom: place.priceFrom || null,
            priceTo: place.priceTo || null,
            openingHours: place.openingHours || [],
            amenities: place.amenities || [],
            // status: place.status || "draft", // Remove status from wizard
          },
          currentStep: 1,
        });
      },

      setSelectedPlace: (place) => {
        set({ selectedPlace: place });
      },

      clearError: () => {
        set({ error: null });
      },

      reset: () => {
        set({
          places: [],
          selectedPlace: null,
          featuredPlaces: [],
          nearbyPlaces: [],
          loading: false,
          error: null,
          pagination: {
            page: 1,
            limit: 10,
            total: 0,
            totalPages: 0,
          },
        });
      },
    }),
    { name: "PlaceStore" },
  ),
);

export default usePlaceStore;
